window.CB_DEFAULT_DATA = {"version":"4.0.0","title":"固定性補綴学 暗記アプリ（文脈明確版）","questions":[{"id":"q001","number":1,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスアップ時、咬頭嵌合位で各咬頭に咬合接触点を付与する接触様式を何というか。","answer":"多点均等接触","explanation":"資料の記載：咬頭嵌合位で各咬頭に咬合接触点を付与（多点均等接触）\n\n補足：各咬頭に偏りなく接触点を与え、力を分散させる。","source":"資料7 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p5","path":"assets/sourcepages/s7_p5.jpg"}]},{"id":"q002","number":2,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスアップ時、前方運動で臼歯部を離開させる誘導を何というか。","answer":"アンテリアガイダンス","explanation":"資料の記載：前方運動：臼歯部は離開（アンテリアガイダンス）\n\n補足：前歯部の誘導により臼歯部が離開する。","source":"資料7 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p5","path":"assets/sourcepages/s7_p5.jpg"}]},{"id":"q003","number":3,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスアップ時、プラークが停滞して歯周炎を惹起しやすい過度な歯冠豊隆を何というか。","answer":"オーバーカントゥア","explanation":"資料の記載：オーバーカントゥア：プラークの停滞→ 歯周炎を惹起\n\n補足：資料では「オーバーカントゥア：プラークの停滞→歯周炎を惹起」と示されている。","source":"資料7 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p6","path":"assets/sourcepages/s7_p6.jpg"}]},{"id":"q004","number":4,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスアップ時、食物の流れによって辺縁歯肉に外傷を生じやすい不足した歯冠豊隆を何というか。","answer":"アンダーカントゥア","explanation":"資料の記載：アンダーカントゥア：食物の流れ→ 辺縁歯肉の外傷\n\n補足：資料では「アンダーカントゥア：食物の流れ→辺縁歯肉の外傷」と示されている。","source":"資料7 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p6","path":"assets/sourcepages/s7_p6.jpg"}]},{"id":"q005","number":5,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスアップ時、歯頸部の立ち上がり部の形態を何というか。","answer":"エマージェンスプロファイル","explanation":"資料の記載：エマージェンスプロファイル：歯頸部の立ち上がり部の形態\n\n補足：資料の定義をそのまま用いた。","source":"資料7 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p6","path":"assets/sourcepages/s7_p6.jpg"}]},{"id":"q006","number":6,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスアップで接触点を正しく回復するとき、歯間部に確保すべき空隙を何というか。","answer":"鼓形空隙","explanation":"資料の記載：適切な鼓形空隙を確保する\n\n補足：歯間乳頭や清掃性に配慮して適切に回復する。","source":"資料7 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p7","path":"assets/sourcepages/s7_p7.jpg"}]},{"id":"q007","number":7,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"前歯部のワックスアップ時、接触面は上下的にどのような形態とするか。","answer":"上下的な楕円形","explanation":"資料の記載：前歯：上下的な楕円形／唇舌的に中央\n\n補足：前歯では上下方向に長い楕円形となる。","source":"資料7 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p8","path":"assets/sourcepages/s7_p8.jpg"}]},{"id":"q008","number":8,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"前歯部のワックスアップ時、接触点の位置は唇舌的にどこに設定するか。","answer":"中央","explanation":"資料の記載：唇舌的に中央／上下的に切縁側1/3 ～1/4\n\n補足：前歯では唇舌的中央に設定する。","source":"資料7 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p8","path":"assets/sourcepages/s7_p8.jpg"}]},{"id":"q009","number":9,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"前歯部のワックスアップ時、接触点の位置は上下的に切縁側のどの範囲に設定するか。","answer":"1/3〜1/4","explanation":"資料の記載：上下的に切縁側1/3 ～1/4\n\n補足：切縁寄りに設定する。","source":"資料7 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p8","path":"assets/sourcepages/s7_p8.jpg"}]},{"id":"q010","number":10,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"臼歯部のワックスアップ時、接触面は頰舌的にどのような形態とするか。","answer":"頰舌的な楕円形","explanation":"資料の記載：臼歯：頰舌的な楕円形／頰舌的に頬側1/3\n\n補足：臼歯では頰舌方向に長い楕円形となる。","source":"資料7 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p8","path":"assets/sourcepages/s7_p8.jpg"}]},{"id":"q011","number":11,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"臼歯部のワックスアップ時、接触点の位置は頰舌的にどこに設定するか。","answer":"頰側1/3","explanation":"資料の記載：頰舌的に頬側1/3／上下的に咬合面側1/3 ～1/4\n\n補足：舌側ではなく頰側寄りに設定する。","source":"資料7 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p8","path":"assets/sourcepages/s7_p8.jpg"}]},{"id":"q012","number":12,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"臼歯部のワックスアップ時、接触点の位置は上下的に咬合面側のどの範囲に設定するか。","answer":"1/3〜1/4","explanation":"資料の記載：上下的に咬合面側1/3 ～1/4\n\n補足：咬合面寄りに設定する。","source":"資料7 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p8","path":"assets/sourcepages/s7_p8.jpg"}]},{"id":"q013","number":13,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスパターンの接触点は鋳造収縮で緩くなるため、近遠心的にどの程度大きめに製作するか。","answer":"0.05〜0.1mm","explanation":"資料の記載：鋳造収縮により緩くなるので、あらかじめ近遠心的に0.05～0.1mm大きめに製作\n\n補足：鋳造後に接触が緩くなることを防ぐ。","source":"資料7 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p8","path":"assets/sourcepages/s7_p8.jpg"}]},{"id":"q014","number":14,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"インレーワックスを少量ずつ盛り上げて歯冠形態を形成するワックスアップ法を何というか。","answer":"盛り上げ法","explanation":"資料の記載：ワックスアップの実際（盛り上げ法）（P230）\n\n補足：操作が容易だが、全体の温度上昇に注意する。","source":"資料7 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p10","path":"assets/sourcepages/s7_p10.jpg"}]},{"id":"q015","number":15,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスアップ法のうち、ワックスシートを歯型へ圧接して形成する方法を何というか。","answer":"圧接法","explanation":"資料の記載：２．圧接法／３．浸漬法（ディッピング法）\n\n補足：軟化温度が低く、変形が少ない。","source":"資料7 p9","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p9","path":"assets/sourcepages/s7_p9.jpg"}]},{"id":"q016","number":16,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスアップ法のうち、ディッピング法とも呼ばれる方法を何というか。","answer":"浸漬法","explanation":"資料の記載：３．浸漬法（ディッピング法）\n\n補足：ディッピング法とも呼ばれる。","source":"資料7 p9","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p9","path":"assets/sourcepages/s7_p9.jpg"}]},{"id":"q017","number":17,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスアップ法のうち、ワックスコーンテクニックとも呼ばれる方法を何というか。","answer":"ドロップオンテクニック","explanation":"資料の記載：４．ドロップオンテクニック（ワックスコーンテクニック）\n\n補足：ワックスコーンテクニックとも呼ばれる。","source":"資料7 p9","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p9","path":"assets/sourcepages/s7_p9.jpg"}]},{"id":"q018","number":18,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"盛り上げ法によるワックスアップの前に、歯型・隣在歯隣接面・対合歯咬合面へ何を塗布するか。","answer":"分離剤","explanation":"資料の記載：歯型，隣在歯隣接面，対合歯咬合面に分離剤塗布\n\n補足：歯型・隣在歯・対合歯に塗布する。","source":"資料7 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p10","path":"assets/sourcepages/s7_p10.jpg"}]},{"id":"q019","number":19,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"盛り上げ法によるワックスアップで、軸面から少量ずつ盛り上げて歯冠形態を概形成する材料は何か。","answer":"インレーワックス","explanation":"資料の記載：軸面から少量ずつインレーワックスを盛り上げ歯冠形態の概形成\n\n補足：軸面から少量ずつ盛り上げる。","source":"資料7 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p10","path":"assets/sourcepages/s7_p10.jpg"}]},{"id":"q020","number":20,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスアップ後、咬合接触の確認に用いるものは何か。","answer":"咬合紙","explanation":"資料の記載：咬合紙を用いて咬合接触の確認\n\n補足：咬合面形成時に接触部を確認する。","source":"資料7 p11","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p11","path":"assets/sourcepages/s7_p11.jpg"}]},{"id":"q021","number":21,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスパターンの研磨には、綿花のほかに何を用いるか。","answer":"ストッキング","explanation":"資料の記載：綿花やストッキングでワックスパターンを研磨\n\n補足：綿花やストッキングで表面を仕上げる。","source":"資料7 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p12","path":"assets/sourcepages/s7_p12.jpg"}]},{"id":"q022","number":22,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"試適・仮着時にクラウンを取り外しやすくするため、ワックスパターンに付与する球状の部分を何というか。","answer":"リムーバルノブ","explanation":"資料の記載：試適，仮着時の取り外しのために球状のリムーバルノブを付与\n\n補足：完成したクラウンの取り外しを容易にする。","source":"資料7 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p12","path":"assets/sourcepages/s7_p12.jpg"}]},{"id":"q023","number":23,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"耐火材と結合材を組み合わせ、鋳造収縮を補償する材料を何というか。","answer":"埋没材","explanation":"資料の記載：埋没材：耐火材と結合材の組み合わせで鋳造収縮を補償\n\n補足：耐火材と結合材の組合せで構成される。","source":"資料7 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p13","path":"assets/sourcepages/s7_p13.jpg"}]},{"id":"q024","number":24,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"埋没材を構成する成分のうち、高温に耐える材料を何というか。","answer":"耐火材","explanation":"資料の記載：埋没材：耐火材と結合材の組み合わせで鋳造収縮を補償\n\n補足：シリカなどが該当する。","source":"資料7 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p13","path":"assets/sourcepages/s7_p13.jpg"}]},{"id":"q025","number":25,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"埋没材を構成する成分のうち、耐火材を結合させる材料を何というか。","answer":"結合材","explanation":"資料の記載：埋没材：耐火材と結合材の組み合わせで鋳造収縮を補償\n\n補足：石膏系やリン酸塩系がある。","source":"資料7 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p13","path":"assets/sourcepages/s7_p13.jpg"}]},{"id":"q026","number":26,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"埋没材の耐火材として用いられるSiO₂を何というか。","answer":"シリカ","explanation":"資料の記載：１）シリカ（SiO2\n\n補足：二酸化ケイ素で、クリストバライトや石英を用いる。","source":"資料7 p15","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p15","path":"assets/sourcepages/s7_p15.jpg"}]},{"id":"q027","number":27,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"リン酸塩系埋没材で、リン酸塩と組み合わせる金属酸化物の代表例は何か。","answer":"マグネシア","explanation":"資料の記載：リン酸塩（リン酸二水素アンモニウムなど）と金属酸化物（マグネシアなど）\n\n補足：アルミナやジルコニアも用いられる。","source":"資料7 p15","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p15","path":"assets/sourcepages/s7_p15.jpg"}]},{"id":"q028","number":28,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"融点が1,000℃以下の、ほとんどの歯科用合金に用いる埋没材は何か。","answer":"石膏系埋没材","explanation":"資料の記載：１）石膏系埋没材（融点が1,000℃以下の）ほとんどの歯科用合金用\n\n補足：多くの歯科用合金に用いられる。","source":"資料7 p15","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p15","path":"assets/sourcepages/s7_p15.jpg"}]},{"id":"q029","number":29,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"石膏系埋没材を700℃以上に加熱して石膏が分解すると生じやすい鋳造欠陥は何か。","answer":"鋳肌荒れ","explanation":"資料の記載：＊700℃以上で石膏が分解→ 鋳造欠陥（鋳肌荒れ）\n\n補足：石膏の分解が原因となる。","source":"資料7 p15","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p15","path":"assets/sourcepages/s7_p15.jpg"}]},{"id":"q030","number":30,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"融点が1,000℃以上の高溶金属に用いる埋没材は何か。","answer":"リン酸塩系埋没材","explanation":"資料の記載：２）リン酸塩系埋没材（融点が1,000℃以上の）高溶金属用\n\n補足：高温に耐えられる結合材を用いる。","source":"資料7 p15","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p15","path":"assets/sourcepages/s7_p15.jpg"}]},{"id":"q031","number":31,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"クリストバライトと石英を含み、急速加熱して使用する埋没材を何というか。","answer":"急速加熱型埋没材","explanation":"資料の記載：急速加熱型埋没材（P235）／↑ クリストバライトと石英\n\n補足：クリストバライトと石英など複数の耐火材を配合する。","source":"資料7 p16","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p16","path":"assets/sourcepages/s7_p16.jpg"}]},{"id":"q032","number":32,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"ワックスパターンへ植立し、溶融金属の流入路となるものを何というか。","answer":"スプルー","explanation":"資料の記載：１．スプルーの植立／２．エアベント\n\n補足：ワックスの厚い部分へ植立する。","source":"資料7 p17","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p17","path":"assets/sourcepages/s7_p17.jpg"}]},{"id":"q033","number":33,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"スプルーは、ワックスパターンのどの部位から厚い部分へ植立するか。","answer":"非機能咬頭外斜面","explanation":"資料の記載：非機能咬頭外斜面でワックスの厚い部分に植立\n\n補足：機能咬頭を避け、厚い部分へ植立する。","source":"資料7 p17","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p17","path":"assets/sourcepages/s7_p17.jpg"}]},{"id":"q034","number":34,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"鋳型内の空気やガスを排出するために付与する通気路を何というか。","answer":"エアベント","explanation":"資料の記載：２．エアベント／３．界面活性剤の塗布\n\n補足：背圧多孔の防止に用いる。","source":"資料7 p17","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p17","path":"assets/sourcepages/s7_p17.jpg"}]},{"id":"q035","number":35,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"エアベントのうち、ベントがワックスパターンに直結するものを何というか。","answer":"オープンベント","explanation":"資料の記載：オープンベント／：ベントがワックスパターンに直結\n\n補足：ワックスパターンへ直接つながる。","source":"資料7 p17","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p17","path":"assets/sourcepages/s7_p17.jpg"}]},{"id":"q036","number":36,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"エアベントのうち、ベントがワックスパターンに直結しないものを何というか。","answer":"ブラインドベント","explanation":"資料の記載：ブラインドベント：ベントがワックスパターンに直結しない\n\n補足：鋳型内の空気排出を補助する。","source":"資料7 p17","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p17","path":"assets/sourcepages/s7_p17.jpg"}]},{"id":"q037","number":37,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"通気性の悪いリン酸塩系埋没材にエアベントを付与することで防止する鋳造欠陥は何か。","answer":"背圧多孔","explanation":"資料の記載：通気性の悪いリン酸塩系埋没材に付与→ 鋳造欠陥（背圧多孔）防止\n\n補足：鋳型内の空気残留による凹みを防ぐ。","source":"資料7 p17","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p17","path":"assets/sourcepages/s7_p17.jpg"}]},{"id":"q038","number":38,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"埋没前、ワックスパターン表面のぬれを良くするために何を塗布するか。","answer":"界面活性剤","explanation":"資料の記載：３．界面活性剤の塗布\n\n補足：気泡由来の突起を防ぐ。","source":"資料7 p17","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p17","path":"assets/sourcepages/s7_p17.jpg"}]},{"id":"q039","number":39,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"埋没時、硬化膨張と加熱膨張を得るために鋳造リング内面へ巻くものを何というか。","answer":"キャスティングライナー","explanation":"資料の記載：４．キャスティングライナーfor 硬化膨張and 加熱膨張\n\n補足：鋳造リング内に巻いて膨張を許容する。","source":"資料7 p17","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p17","path":"assets/sourcepages/s7_p17.jpg"}]},{"id":"q040","number":40,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"埋没材への気泡混入を減らし、鋳造体の突起などを防止するために用いる機器は何か。","answer":"真空練和器","explanation":"資料の記載：真空練和器の使用→ 鋳造欠陥（突起など）防止\n\n補足：突起などの鋳造欠陥を減らす。","source":"資料7 p18","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p18","path":"assets/sourcepages/s7_p18.jpg"}]},{"id":"q041","number":41,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"膨張量が一定で寸法精度が正確な、一般的な埋没法を何というか。","answer":"単一埋没法","explanation":"資料の記載：単一埋没法：一般的．膨張量が一定で寸法精度が正確．\n\n補足：寸法精度が安定する。","source":"資料7 p18","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p18","path":"assets/sourcepages/s7_p18.jpg"}]},{"id":"q042","number":42,"unit":"第1単元 ワックスアップ・埋没","importance":2,"type":"short","question":"気泡の混入を最小にし、大きな硬化膨張を期待できる埋没法を何というか。","answer":"二重埋没法","explanation":"資料の記載：二重埋没法：気泡の混入最小．大きな硬化膨張を期待できる．\n\n補足：精密な表面形成に有利である。","source":"資料7 p18","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p18","path":"assets/sourcepages/s7_p18.jpg"}]},{"id":"q043","number":43,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"歯冠の全部を被覆する歯冠補綴装置を何というか。","answer":"クラウン","explanation":"資料の記載：クラウンの定義と種類（P1, 80）\n\n補足：歯冠を被覆して形態と機能を回復する装置の総称。","source":"資料8 p2","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p2","path":"assets/sourcepages/s8_p2.jpg"}]},{"id":"q044","number":44,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"歯冠全体を単一の材料で製作するクラウンを何というか。","answer":"ジャケットクラウン","explanation":"資料の記載：（レジンジャケットクラウンを含む）\n\n補足：金属を用いない全部被覆冠である。","source":"資料8 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p3","path":"assets/sourcepages/s8_p3.jpg"}]},{"id":"q045","number":45,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":1,"type":"short","question":"ジャケットクラウンのうち、すべてセラミックで製作するものを何というか。","answer":"オールセラミッククラウン","explanation":"資料の記載：①オールセラミッククラウン：すべてセラミック\n\n補足：歯冠色材料のみで作られる。","source":"資料8 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p3","path":"assets/sourcepages/s8_p3.jpg"}]},{"id":"q046","number":46,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":1,"type":"short","question":"ジャケットクラウンのうち、すべてレジンで製作するものを何というか。","answer":"ハイブリッド型コンポジットレジンクラウン","explanation":"資料の記載：②ハイブリッド型コンポジットレジンクラウン：すべてレジン\n\n補足：レジンジャケットクラウンを含む。","source":"資料8 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p3","path":"assets/sourcepages/s8_p3.jpg"}]},{"id":"q047","number":47,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"PEEKの正式名称は何か。","answer":"ポリエーテルエーテルケトン","explanation":"資料の記載：③PEEK冠：すべてPEEK（ポリエーテルエーテルケトン）\n\n補足：PEEK冠の材料名である。","source":"資料8 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p3","path":"assets/sourcepages/s8_p3.jpg"}]},{"id":"q048","number":48,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"オールセラミッククラウンの前歯部支台歯形成で、切縁の削除量はどの程度か。","answer":"1.5〜2.0mm","explanation":"資料の記載：前歯：切縁の削除量1.5～2.0 mm\n\n補足：十分な材料厚を確保する。","source":"資料8 p4","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p4","path":"assets/sourcepages/s8_p4.jpg"}]},{"id":"q049","number":49,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"オールセラミッククラウンの前歯部支台歯形成で、切縁は歯軸に対して約何度に形成するか。","answer":"約45°","explanation":"資料の記載：歯軸に対して約45°\n\n補足：切縁形態に沿って形成する。","source":"資料8 p4","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p4","path":"assets/sourcepages/s8_p4.jpg"}]},{"id":"q050","number":50,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"オールセラミッククラウンの臼歯部支台歯形成で、咬合面の削除量はどの程度か。","answer":"1.5〜2.0mm","explanation":"資料の記載：臼歯：咬合面の削除量1.5～2.0 mm\n\n補足：咬合面でも十分な材料厚が必要。","source":"資料8 p4","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p4","path":"assets/sourcepages/s8_p4.jpg"}]},{"id":"q051","number":51,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"オールセラミッククラウンの前歯部支台歯形成で、唇側面は何面形成とするか。","answer":"3面","explanation":"資料の記載：前歯：唇側面は３面形成\n\n補足：天然歯の曲面に合わせて形成する。","source":"資料8 p4","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p4","path":"assets/sourcepages/s8_p4.jpg"}]},{"id":"q052","number":52,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"オールセラミッククラウンの前歯部支台歯形成で、舌側面の削除量はどの程度か。","answer":"約1.0mm","explanation":"資料の記載：舌側面の削除量約1.0 mm\n\n補足：舌側にも材料厚を確保する。","source":"資料8 p4","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p4","path":"assets/sourcepages/s8_p4.jpg"}]},{"id":"q053","number":53,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"オールセラミッククラウンの支台歯形成で、全周に付与する幅1.0〜1.2mmのフィニッシュラインは何か。","answer":"ディープシャンファー","explanation":"資料の記載：全周ディープシャンファー（幅1.0～1.2 mm）\n\n補足：幅1.0〜1.2mmで形成する。","source":"資料8 p4","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p4","path":"assets/sourcepages/s8_p4.jpg"}]},{"id":"q054","number":54,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"オールセラミッククラウンの支台歯形成で、ディープシャンファーのほかに用いるフィニッシュラインは何か。","answer":"ラウンデッドショルダー","explanation":"資料の記載：全周ディープシャンファーor ラウンデッドショルダー\n\n補足：鋭角を避けた丸みのある形態が必要。","source":"資料8 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p5","path":"assets/sourcepages/s8_p5.jpg"}]},{"id":"q055","number":55,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":1,"type":"short","question":"補助的保持形態（グルーブやキャビティなど）は基本的に付与しない理由は何か。","answer":"スキャン時や加工時の精度に影響するため","explanation":"資料の記載：補助的保持形態（グルーブやキャビティなど）は基本的に付与しない／理由：スキャン時や加工時の精度に影響するため\n\n補足：グルーブなどは読み取りや加工精度を低下させる。","source":"資料8 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p5","path":"assets/sourcepages/s8_p5.jpg"}]},{"id":"q056","number":56,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"CAD/CAM冠の臼歯部支台歯形成で、咬合面の削除量はどの程度以上必要か。","answer":"1.0〜1.5mm","explanation":"資料の記載：臼歯：咬合面の削除量1.0～1.5 mm以上\n\n補足：材料強度を確保するための削除量。","source":"資料8 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p6","path":"assets/sourcepages/s8_p6.jpg"}]},{"id":"q057","number":57,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"CAD/CAM冠の支台歯形成で、軸面テーパーは片面何度程度とするか。","answer":"6〜10°","explanation":"資料の記載：軸面テーパー：片面6～10°程度\n\n補足：維持力と装着性のバランスをとる。","source":"資料8 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p6","path":"assets/sourcepages/s8_p6.jpg"}]},{"id":"q058","number":58,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"CAD/CAM冠の支台歯形成で、軸面は均一にどの程度以上削除するか。","answer":"1.0mm以上","explanation":"資料の記載：削除量：均一に1.0 mm以上\n\n補足：均一な材料厚を確保する。","source":"資料8 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p6","path":"assets/sourcepages/s8_p6.jpg"}]},{"id":"q059","number":59,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"CAD/CAM冠の支台歯形成で、フィニッシュラインの幅はどの程度以上必要か。","answer":"0.8mm以上","explanation":"資料の記載：（幅0.8 mm以上）／臼歯：咬合面の削除量1.0～1.5 mm以上\n\n補足：ディープシャンファーまたはラウンデッドショルダーを用いる。","source":"資料8 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p6","path":"assets/sourcepages/s8_p6.jpg"}]},{"id":"q060","number":60,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"歯冠全体をハイブリッド型コンポジットレジンで製作するクラウンを何というか。","answer":"ハイブリッド型コンポジットレジン","explanation":"資料の記載：ハイブリッド型コンポジットレジンクラウン（P283）\n\n補足：マトリックスレジンをフィラーで強化した材料。","source":"資料8 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p7","path":"assets/sourcepages/s8_p7.jpg"}]},{"id":"q061","number":61,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"陶材よりも技工操作が容易で低コストなレジン製ジャケットクラウンを何というか。","answer":"ハイブリッド型コンポジットレジン","explanation":"資料の記載：ハイブリッド型コンポジットレジンクラウン（P283）\n\n補足：ジャケットクラウン材料として用いられる。","source":"資料8 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p7","path":"assets/sourcepages/s8_p7.jpg"}]},{"id":"q062","number":62,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"接着性レジンセメントを用いて装着するレジン製ジャケットクラウンを何というか。","answer":"ハイブリッド型コンポジットレジン","explanation":"資料の記載：ハイブリッド型コンポジットレジンクラウン（P283）\n\n補足：レジンの粘りにより衝撃へ抵抗する。","source":"資料8 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p7","path":"assets/sourcepages/s8_p7.jpg"}]},{"id":"q063","number":63,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"ハイブリッド型コンポジットレジンクラウンの装着に必須のセメントは何か。","answer":"接着性レジンセメント","explanation":"資料の記載：③接着性レジンセメントの使用が必須\n\n補足：吸水性や接着の問題から強固な接着が必要。","source":"資料8 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p7","path":"assets/sourcepages/s8_p7.jpg"}]},{"id":"q064","number":64,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":1,"type":"short","question":"ジャケットクラウンの適応症のうち、歯の色調に問題がある歯を何というか。","answer":"変色歯","explanation":"資料の記載：①変色歯／②エナメル質形成不全症\n\n補足：審美回復を目的に適応する。","source":"資料8 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p8","path":"assets/sourcepages/s8_p8.jpg"}]},{"id":"q065","number":65,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":1,"type":"short","question":"ジャケットクラウンの適応症のうち、エナメル質の形成に異常がある病態を何というか。","answer":"エナメル質形成不全症","explanation":"資料の記載：②エナメル質形成不全症／③形態異常歯\n\n補足：歯冠色材料で外観を回復する。","source":"資料8 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p8","path":"assets/sourcepages/s8_p8.jpg"}]},{"id":"q066","number":66,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":1,"type":"short","question":"ジャケットクラウンの禁忌となる、歯ぎしりを何というか。","answer":"ブラキシズム","explanation":"資料の記載：③ブラキシズムやクレンチングの強い患者\n\n補足：強い咬合力で破折や摩耗の危険が高まる。","source":"資料8 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p8","path":"assets/sourcepages/s8_p8.jpg"}]},{"id":"q067","number":67,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"CAD/CAM冠は、どの方法で製作されるクラウンか。","answer":"CAD/CAM法","explanation":"資料の記載：CAD/CAM法で製作されるクラウンのための支台歯形成（P148-9）\n\n補足：既製ブロックを機械加工する。","source":"資料8 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p5","path":"assets/sourcepages/s8_p5.jpg"}]},{"id":"q068","number":68,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"ハイブリッド型コンポジットレジンクラウンの築盛で、最初に用いるレジンは何か。","answer":"オペークレジン","explanation":"資料の記載：①オペークレジン→ ②デンティン色レジン→ ③エナメル色レジン\n\n補足：下地色を遮蔽する。","source":"資料8 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p10","path":"assets/sourcepages/s8_p10.jpg"}]},{"id":"q069","number":69,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"ハイブリッド型コンポジットレジンクラウンの築盛で、オペークレジンの次に用いるレジンは何か。","answer":"デンティン色レジン","explanation":"資料の記載：①オペークレジン→ ②デンティン色レジン→ ③エナメル色レジン\n\n補足：象牙質色を再現する。","source":"資料8 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p10","path":"assets/sourcepages/s8_p10.jpg"}]},{"id":"q070","number":70,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"ハイブリッド型コンポジットレジンクラウンの築盛で、デンティン色レジンの次に用いるレジンは何か。","answer":"エナメル色レジン","explanation":"資料の記載：①オペークレジン→ ②デンティン色レジン→ ③エナメル色レジン\n\n補足：表層の透明感を再現する。","source":"資料8 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p10","path":"assets/sourcepages/s8_p10.jpg"}]},{"id":"q071","number":71,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"レジン築盛時に残ると、気泡の混入とともに物性低下の原因となる表面層を何というか。","answer":"未重合層","explanation":"資料の記載：点：未重合層，気泡の混入→ 物性低下\n\n補足：気泡混入とともに物性を下げる。","source":"資料8 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p10","path":"assets/sourcepages/s8_p10.jpg"}]},{"id":"q072","number":72,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"レジンブロックを切削加工してクラウンを製作する方法を何というか。","answer":"機械加工法","explanation":"資料の記載：機械加工法（P287）／レジンブロックを切削加工して製作\n\n補足：高密度・高品質なブロックを使用できる。","source":"資料8 p11","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p11","path":"assets/sourcepages/s8_p11.jpg"}]},{"id":"q073","number":73,"unit":"第2単元 ジャケットクラウン・CAD/CAM冠","importance":2,"type":"short","question":"レジンブロックの機械加工法では、何色のレジン層がないため支台歯の色を遮断できないか。","answer":"オペーク色","explanation":"資料の記載：点：①オペーク色により支台歯の色を遮断できない\n\n補足：機械加工ブロックではオペーク層を自由に築盛できない。","source":"資料8 p11","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p11","path":"assets/sourcepages/s8_p11.jpg"}]},{"id":"q074","number":74,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"金属製のクラウンの一部を歯冠色材料で被覆した冠を何というか。","answer":"前装冠","explanation":"資料の記載：前装冠（P82-84）\n\n補足：金属の強度と歯冠色材料の審美性を組み合わせる。","source":"資料9 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p3","path":"assets/sourcepages/s9_p3.jpg"}]},{"id":"q075","number":75,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"前装冠のうち、前装部が陶材であるものを何というか。","answer":"陶材焼付冠","explanation":"資料の記載：陶材焼付冠／：前装部が陶材\n\n補足：金属に陶材を焼き付ける。","source":"資料9 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p3","path":"assets/sourcepages/s9_p3.jpg"}]},{"id":"q076","number":76,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"前装冠のうち、前装部がレジンであるものを何というか。","answer":"レジン前装冠","explanation":"資料の記載：レジン前装冠：前装部がレジン\n\n補足：金属フレームにレジンを前装する。","source":"資料9 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p3","path":"assets/sourcepages/s9_p3.jpg"}]},{"id":"q077","number":77,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"前装部に何のための構造が必要か。","answer":"機械的維持","explanation":"資料の記載：前装部に機械的維持のための構造が必要\n\n補足：レジンは金属へ直接強固に結合しにくいため必要。","source":"資料9 p4","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p4","path":"assets/sourcepages/s9_p4.jpg"}]},{"id":"q078","number":78,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"レジン前装冠で経時的に生じることがある色調変化を何というか。","answer":"変色","explanation":"資料の記載：③経時的に変色することがある\n\n補足：陶材より長期色調安定性が劣る。","source":"資料9 p4","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p4","path":"assets/sourcepages/s9_p4.jpg"}]},{"id":"q079","number":79,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":1,"type":"short","question":"レジン前装冠の適応症のうち、動揺歯を連結して固定する用途を何というか。","answer":"一次固定","explanation":"資料の記載：③動揺歯の一次固定／④コーヌステレスコープクラウン外冠\n\n補足：連結して動揺を抑える目的で用いる。","source":"資料9 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p5","path":"assets/sourcepages/s9_p5.jpg"}]},{"id":"q080","number":80,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":1,"type":"short","question":"レジン前装冠の禁忌となる、歯ぎしりを何というか。","answer":"ブラキシズム","explanation":"資料の記載：①咬合力の強い患者やブラキシズム症例\n\n補足：強い咬合力で前装部が摩耗・破折しやすい。","source":"資料9 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p5","path":"assets/sourcepages/s9_p5.jpg"}]},{"id":"q081","number":81,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"前装冠の前歯部支台歯形成で、切縁の削除量はどの程度か。","answer":"1.5〜2.0mm","explanation":"資料の記載：前歯：切縁の削除量1.5～2.0 mm\n\n補足：前装材料と金属の厚みを確保する。","source":"資料9 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p6","path":"assets/sourcepages/s9_p6.jpg"}]},{"id":"q082","number":82,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"前装冠の臼歯部支台歯形成で、咬合面の削除量はどの程度か。","answer":"1.0〜1.5mm","explanation":"資料の記載：臼歯：咬合面の削除量1.0～1.5 mm\n\n補足：ジャケットクラウンよりやや少ない。","source":"資料9 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p6","path":"assets/sourcepages/s9_p6.jpg"}]},{"id":"q083","number":83,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"前装冠の支台歯形成で、前装部分に付与する幅1.0〜1.2mm以上のフィニッシュラインは何か。","answer":"ディープシャンファー","explanation":"資料の記載：前装部分ディープシャンファー（幅1.0～1.2 mm以上）\n\n補足：幅1.0〜1.2mm以上を確保する。","source":"資料9 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p6","path":"assets/sourcepages/s9_p6.jpg"}]},{"id":"q084","number":84,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"前装冠の支台歯形成で、前装しない部分に付与するフィニッシュラインは何か。","answer":"シャンファー","explanation":"資料の記載：前装しない部分シャンファー\n\n補足：金属のみの部分では削除量を抑えられる。","source":"資料9 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p6","path":"assets/sourcepages/s9_p6.jpg"}]},{"id":"q085","number":85,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"レジン前装冠で、レジンの機械的維持に用いる球状の維持装置を何というか。","answer":"リテンションビーズ","explanation":"資料の記載：リテンションビーズなど／（粒径：0.15～0.2mm）\n\n補足：金属表面に凹凸を作りレジンを保持する。","source":"資料9 p9","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p9","path":"assets/sourcepages/s9_p9.jpg"}]},{"id":"q086","number":86,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"レジン前装冠に用いるリテンションビーズの粒径はどの程度か。","answer":"0.15〜0.2mm","explanation":"資料の記載：リテンションビーズなど（粒径：0.15～0.2mm）\n\n補足：前装部の機械的維持に用いる。","source":"資料9 p9","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p9","path":"assets/sourcepages/s9_p9.jpg"}]},{"id":"q087","number":87,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"レジン前装冠のレジンと金属の接着で、機械的維持とともに作用するものは何か。","answer":"機能性モノマー","explanation":"資料の記載：* 機械的維持と機能性モノマーによる接着による\n\n補足：金属接着性プライマーに含まれる。","source":"資料9 p9","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p9","path":"assets/sourcepages/s9_p9.jpg"}]},{"id":"q088","number":88,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"レジン前装冠の金属前装面に行う、アルミナ粒子を用いた表面処理を何というか。","answer":"アルミナサンドブラスト処理","explanation":"資料の記載：アルミナサンドブラスト処理\n\n補足：表面粗さを増して接着を高める。","source":"資料9 p23","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p23","path":"assets/sourcepages/s9_p23.jpg"}]},{"id":"q089","number":89,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"レジン前装冠で、レジン築盛前に前装面辺縁部から削除するものは何か。","answer":"リテンションビーズ","explanation":"資料の記載：*レジン築盛前に前装面辺縁部のリテンションビーズは削除\n\n補足：辺縁の適合と仕上げを妨げるため除去する。","source":"資料9 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p10","path":"assets/sourcepages/s9_p10.jpg"}]},{"id":"q090","number":90,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"レジン前装冠の荒研磨に用いる研磨器材を1つ答えよ。","answer":"ダイヤモンドポイント","explanation":"資料の記載：荒研磨：ダイヤモンドポイント，カーバイドバー，カーボランダムポイントなど\n\n補足：カーバイドバーやカーボランダムポイントも用いる。","source":"資料9 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p12","path":"assets/sourcepages/s9_p12.jpg"}]},{"id":"q091","number":91,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"レジン前装冠の中研磨に用いる研磨器材は何か。","answer":"シリコーンポイント","explanation":"資料の記載：中研磨：シリコーンポイントなど\n\n補足：荒研磨後に表面を滑沢にする。","source":"資料9 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p12","path":"assets/sourcepages/s9_p12.jpg"}]},{"id":"q092","number":92,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"レジン前装冠の仕上げ研磨に用いる研磨器材を1つ答えよ。","answer":"バフ","explanation":"資料の記載：仕上げ研磨：バフor ホイール＋ルージュor ダイヤモンド微粒子含むペ—スト\n\n補足：ホイールも用い、ルージュやペーストを併用する。","source":"資料9 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p12","path":"assets/sourcepages/s9_p12.jpg"}]},{"id":"q093","number":93,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"前装材料として用いる陶材を金属に溶着させた前装冠を何というか。","answer":"陶材焼付冠","explanation":"資料の記載：陶材焼付冠（P83）／前装材料として用いる陶材を金属に溶着させた前装冠\n\n補足：PFMクラウンとも呼ばれる。","source":"資料9 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p13","path":"assets/sourcepages/s9_p13.jpg"}]},{"id":"q094","number":94,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"陶材焼付冠の陶材は、約何℃の焼成温度から室温まで徐冷すると熱収縮するか。","answer":"約950℃","explanation":"資料の記載：焼成温度（約950℃）から室温まで徐冷する際に熱収縮（約0.6～0.8％）\n\n補足：金属の融解温度はこれより十分高い必要がある。","source":"資料9 p14","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p14","path":"assets/sourcepages/s9_p14.jpg"}]},{"id":"q095","number":95,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"陶材の熱膨張係数を金属に近づけるため、陶材へ混入する結晶は何か。","answer":"リューサイト","explanation":"資料の記載：リューサイトの混入→ 陶材の熱膨張係数を金属に近づける\n\n補足：混入量により熱膨張を調整する。","source":"資料9 p14","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p14","path":"assets/sourcepages/s9_p14.jpg"}]},{"id":"q096","number":96,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"陶材焼付用金属には、陶材の焼成温度よりどの程度高い融解温度が必要か。","answer":"150〜260℃","explanation":"資料の記載：陶材の焼成温度よりも150～260℃以上高い融解温度\n\n補足：焼成時に金属が変形しないため。","source":"資料9 p14","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p14","path":"assets/sourcepages/s9_p14.jpg"}]},{"id":"q097","number":97,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"陶材焼付用金属の表面に形成され、陶材との化学的結合に関与するものは何か。","answer":"酸化膜","explanation":"資料の記載：金属表面の酸化膜（In2O3, SiO2, Cr2O3など）→ 陶材との化学的結合\n\n補足：In2O3、SiO2、Cr2O3などが関与する。","source":"資料9 p14","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p14","path":"assets/sourcepages/s9_p14.jpg"}]},{"id":"q098","number":98,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"陶材焼付用金属は、陶材に対するぬれを良くするため接触角がどのようである必要があるか。","answer":"小さい","explanation":"資料の記載：陶材に対するぬれがよいこと（接触角が小さいこと）\n\n補足：接触角が小さいほど陶材が金属へ広がりやすい。","source":"資料9 p14","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p14","path":"assets/sourcepages/s9_p14.jpg"}]},{"id":"q099","number":99,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"金属と陶材の結合様式のうち、金属表面の微細な凹凸に陶材が入り込む結合を何というか。","answer":"機械的結合","explanation":"資料の記載：１）機械的結合／２）化学的結合\n\n補足：嵌合効果による。","source":"資料9 p15","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p15","path":"assets/sourcepages/s9_p15.jpg"}]},{"id":"q100","number":100,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"金属と陶材の結合様式のうち、金属表面の酸化膜を介する結合を何というか。","answer":"化学的結合","explanation":"資料の記載：２）化学的結合／３）結合圧縮応力による結合\n\n補足：陶材と金属の主要な結合機序。","source":"資料9 p15","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p15","path":"assets/sourcepages/s9_p15.jpg"}]},{"id":"q101","number":101,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"金属と陶材の結合様式のうち、両者の熱収縮差によって陶材に圧縮応力を生じさせる結合を何というか。","answer":"結合圧縮応力による結合","explanation":"資料の記載：３）結合圧縮応力による結合／嵌合効果：金属表面の微細な凹凸に陶材が嵌入\n\n補足：陶材の熱膨張係数を金属よりわずかに小さくする。","source":"資料9 p15","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p15","path":"assets/sourcepages/s9_p15.jpg"}]},{"id":"q102","number":102,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"金属と陶材の結合におけるファンデルワールス力の関与は約何％か。","answer":"約3％","explanation":"資料の記載：＊ファンデルワールス力の関与は小さい（約３％）\n\n補足：主要な結合機序ではない。","source":"資料9 p15","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p15","path":"assets/sourcepages/s9_p15.jpg"}]},{"id":"q103","number":103,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"陶材焼付冠で、辺縁部のメタルコーピングを除去したポーセレンマージンを何というか。","answer":"カラーレスマージン","explanation":"資料の記載：１．カラーレスマージン（ポーセレンマージン）\n\n補足：ポーセレンマージンとも呼ばれる。","source":"資料9 p18","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p18","path":"assets/sourcepages/s9_p18.jpg"}]},{"id":"q104","number":104,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"陶材焼付冠で、メタルカラーの厚さをマージン部でほぼゼロにする設計を何というか。","answer":"インビジブルメタルマージン","explanation":"資料の記載：インビジブルメタルマージン／１．カラーレスマージン（ポーセレンマージン）\n\n補足：金属色を目立ちにくくする。","source":"資料9 p18","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p18","path":"assets/sourcepages/s9_p18.jpg"}]},{"id":"q105","number":105,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"インビジブルメタルマージンでは、メタルカラーをどの程度の厚さに薄く仕上げるか。","answer":"0.3mm","explanation":"資料の記載：メタルカラーを0.3mm程度の厚さに薄く仕上げる\n\n補足：試適前に薄く仕上げる。","source":"資料9 p19","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p19","path":"assets/sourcepages/s9_p19.jpg"}]},{"id":"q106","number":106,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"陶材焼付面全体をわずかに一層切削する際に用いる器具は何か。","answer":"カーバイドバー","explanation":"資料の記載：陶材焼付面全体をカーバイドバーを用いてわずかに一層切削\n\n補足：表面の不純物や粗さを整える。","source":"資料9 p19","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p19","path":"assets/sourcepages/s9_p19.jpg"}]},{"id":"q107","number":107,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"陶材焼付面の表面処理で、フッ化水素酸を用いる処理を何というか。","answer":"フッ化水素酸処理","explanation":"資料の記載：４）フッ化水素酸処理／５）ディギャッシング（ガス抜き）\n\n補足：以前は不純物除去目的で行われた。","source":"資料9 p19","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p19","path":"assets/sourcepages/s9_p19.jpg"}]},{"id":"q108","number":108,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"陶材焼付前に行うガス抜きを何というか。","answer":"ディギャッシング","explanation":"資料の記載：５）ディギャッシング（ガス抜き）\n\n補足：ガス抜き・酸化膜形成を目的とする。","source":"資料9 p19","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p19","path":"assets/sourcepages/s9_p19.jpg"}]},{"id":"q109","number":109,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"ディギャッシングは、陶材焼成温度よりやや高い何℃で行うか。","answer":"1,000〜1,050℃","explanation":"資料の記載：陶材焼成温度よりもやや高い温度（1,000～1,050℃）で\n\n補足：陶材焼成温度よりやや高い。","source":"資料9 p19","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p19","path":"assets/sourcepages/s9_p19.jpg"}]},{"id":"q110","number":110,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"ディギャッシングでは、所定温度で何分間係留するか。","answer":"10〜15分","explanation":"資料の記載：10～15分間係留\n\n補足：所定温度で保持する。","source":"資料9 p19","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p19","path":"assets/sourcepages/s9_p19.jpg"}]},{"id":"q111","number":111,"unit":"第3単元 レジン前装冠・陶材焼付冠","importance":2,"type":"short","question":"陶材と金属の結合を補助するため、メタルカラーに行う処理を何というか。","answer":"ボンディングエージェント","explanation":"資料の記載：６）ボンディングエージェント処理／メタルカラーを0.3mm程度の厚さに薄く仕上げる\n\n補足：塗布・加熱して金属へ溶着させる。","source":"資料9 p19","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p19","path":"assets/sourcepages/s9_p19.jpg"}]},{"id":"q112","number":112,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"歯の唇面を薄いセラミックで被覆する修復法を何というか。","answer":"ラミネートベニア","explanation":"資料の記載：ラミネートベニア（P92, 153, 281）\n\n補足：主に前歯の審美改善に用いる。","source":"資料10 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p3","path":"assets/sourcepages/s10_p3.jpg"}]},{"id":"q113","number":113,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"ラミネートベニアを歯の唇面へ接着する際に用いるセメントは何か。","answer":"接着性レジンセメント","explanation":"資料の記載：→接着性レジンセメントによって唇面に接着\n\n補足：薄い修復物を歯質へ強固に接着する。","source":"資料10 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p3","path":"assets/sourcepages/s10_p3.jpg"}]},{"id":"q114","number":114,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"ラミネートベニアの歯質削除は、原則としてどの組織内にとどめるか。","answer":"エナメル質内","explanation":"資料の記載：歯質削除は原則エナメル質内\n\n補足：象牙質露出を避け接着を安定させる。","source":"資料10 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p3","path":"assets/sourcepages/s10_p3.jpg"}]},{"id":"q115","number":115,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"歯質削除を最小限にする「ミニマルインターベンション」の略称は何か。","answer":"MI","explanation":"資料の記載：（MI：ミニマルインターベンション）\n\n補足：Minimal Interventionの略。","source":"資料10 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p3","path":"assets/sourcepages/s10_p3.jpg"}]},{"id":"q116","number":116,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"ラミネートベニアの支台歯形成で、辺縁形態は何とするか。","answer":"シャンファー","explanation":"資料の記載：辺縁形態：シャンファー／切縁から舌側にかけて被覆する場合あり（2mm程度）\n\n補足：薄いシェルに適した辺縁形態。","source":"資料10 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p3","path":"assets/sourcepages/s10_p3.jpg"}]},{"id":"q117","number":117,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"ラミネートベニアで切縁から舌側まで被覆する場合、その範囲は切縁からどの程度か。","answer":"2mm","explanation":"資料の記載：切縁から舌側にかけて被覆する場合あり（2mm程度）\n\n補足：切縁から舌側にかけて被覆する場合がある。","source":"資料10 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p3","path":"assets/sourcepages/s10_p3.jpg"}]},{"id":"q118","number":118,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"ラミネートベニアは、主にどの製作法で作られるか。","answer":"耐火模型法","explanation":"資料の記載：主に耐火模型法にて製作（CAD/CAM法での製作も可能）\n\n補足：CAD/CAM法でも製作できる。","source":"資料10 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p3","path":"assets/sourcepages/s10_p3.jpg"}]},{"id":"q119","number":119,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":1,"type":"short","question":"歯冠全体をセラミックのみで製作するクラウンを何というか。","answer":"オールセラミッククラウン","explanation":"資料の記載：オールセラミッククラウン（P84）\n\n補足：金属を用いないため高い審美性を示す。","source":"資料10 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p7","path":"assets/sourcepages/s10_p7.jpg"}]},{"id":"q120","number":120,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"最も天然歯に近い何を再現するか。","answer":"色調と透過性","explanation":"資料の記載：最も天然歯に近い色調と透過性を再現\n\n補足：歯冠色と光学特性に優れる。","source":"資料10 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p7","path":"assets/sourcepages/s10_p7.jpg"}]},{"id":"q121","number":121,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":1,"type":"short","question":"オールセラミッククラウンの適応症のうち、エナメル質の形成に異常がある病態を何というか。","answer":"エナメル質形成不全症","explanation":"資料の記載：②エナメル質形成不全症／③形態異常歯\n\n補足：審美的回復を目的に適応する。","source":"資料10 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p7","path":"assets/sourcepages/s10_p7.jpg"}]},{"id":"q122","number":122,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":1,"type":"short","question":"オールセラミッククラウンの適応となるアレルギー患者は、何に対するアレルギーを有する患者か。","answer":"金属アレルギー","explanation":"資料の記載：⑥金属アレルギー患者／④歯冠崩壊が著しい症例でかつ全部被覆冠の適応症例\n\n補足：金属を使用しない。","source":"資料10 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p7","path":"assets/sourcepages/s10_p7.jpg"}]},{"id":"q123","number":123,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":1,"type":"short","question":"オールセラミッククラウンの禁忌となる、歯ぎしりを何というか。","answer":"ブラキシズム","explanation":"資料の記載：③ブラキシズムやクレンチングの強い患者\n\n補足：強い咬合力で破折リスクが高くなる。","source":"資料10 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p7","path":"assets/sourcepages/s10_p7.jpg"}]},{"id":"q124","number":124,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"オールセラミッククラウンの支台歯形成で、全周に付与する幅1.0〜1.2mmのフィニッシュラインは何か。","answer":"ディープシャンファー","explanation":"資料の記載：全周ディープシャンファー（幅1.0～1.2 mm）\n\n補足：幅1.0〜1.2mmで形成する。","source":"資料10 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p8","path":"assets/sourcepages/s10_p8.jpg"}]},{"id":"q125","number":125,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"ジルコニアのうち、コーピングに応用される正方晶ジルコニア多結晶体の略称は何か。","answer":"TZP","explanation":"資料の記載：正方晶ジルコニア多結晶体（TZP）：コーピングに応用\n\n補足：正方晶ジルコニア多結晶体。","source":"資料10 p9","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p9","path":"assets/sourcepages/s10_p9.jpg"}]},{"id":"q126","number":126,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"ジルコニアのうち、モノリシッククラウンに応用される部分安定化ジルコニアの略称は何か。","answer":"PSZ","explanation":"資料の記載：部分安定化ジルコニア（PSZ）：モノリシッククラウンに応用\n\n補足：部分安定化ジルコニア。","source":"資料10 p9","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p9","path":"assets/sourcepages/s10_p9.jpg"}]},{"id":"q127","number":127,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"耐火模型上でセラミックスを築盛・焼成するオールセラミッククラウンの製作法を何というか。","answer":"耐火模型法","explanation":"資料の記載：１．耐火模型法／耐火模型上でセラミックスを築盛，焼成する方法\n\n補足：現在は主にラミネートベニアに用いる。","source":"資料10 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p10","path":"assets/sourcepages/s10_p10.jpg"}]},{"id":"q128","number":128,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"鋳型に高温で可塑化したセラミックインゴットをプレス成形する製作法を何というか。","answer":"ロストワックス法","explanation":"資料の記載：２．ロストワックス法／鋳型に高温で可塑化したインゴットをプレス成形\n\n補足：セラミックスを加圧成形する。","source":"資料10 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p10","path":"assets/sourcepages/s10_p10.jpg"}]},{"id":"q129","number":129,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"ステイン用陶材を表面に塗布して歯冠色を再現する方法を何というか。","answer":"ステイニング","explanation":"資料の記載：ステイニング：ステイン用陶材を塗布して歯冠色の再現\n\n補足：表面着色で歯冠色を調整する。","source":"資料10 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p10","path":"assets/sourcepages/s10_p10.jpg"}]},{"id":"q130","number":130,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"デンティン色陶材の上にエナメル色陶材を築盛して色調を再現する方法を何というか。","answer":"レイヤリング","explanation":"資料の記載：レイヤリング：デンティン色陶材上にエナメル色陶材を築盛\n\n補足：層構造で色調と透明感を再現する。","source":"資料10 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p10","path":"assets/sourcepages/s10_p10.jpg"}]},{"id":"q131","number":131,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"現在、オールセラミッククラウンの製作で最も多く用いられている方法は何か。","answer":"CAD/CAM法","explanation":"資料の記載：３．CAD/CAM法／現在，最も多く用いられている方法\n\n補足：現在最も多く用いられる。","source":"資料10 p11","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p11","path":"assets/sourcepages/s10_p11.jpg"}]},{"id":"q132","number":132,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"CAD/CAM法で、インレーやラミネートベニアに用いられるセラミック材料を1つ答えよ。","answer":"長石系","explanation":"資料の記載：長石系やリューサイト：インレー，ラミネートベニア，\n\n補足：リューサイト系も用いられる。","source":"資料10 p11","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p11","path":"assets/sourcepages/s10_p11.jpg"}]},{"id":"q133","number":133,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"CAD/CAM法で、大臼歯のモノリシッククラウンに用いられるセラミック材料は何か。","answer":"二ケイ酸リチウム","explanation":"資料の記載：二ケイ酸リチウム：大臼歯のモノリシッククラウン，\n\n補足：前歯・小臼歯の3ユニット以下のブリッジにも用いる。","source":"資料10 p11","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p11","path":"assets/sourcepages/s10_p11.jpg"}]},{"id":"q134","number":134,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"CAD/CAM法でジルコニアを切削するとき、切削前のジルコニアはどのような焼結状態か。","answer":"半焼結","explanation":"資料の記載：半焼結のジルコニアを切削→ 完全焼結（1,400～1,600℃）\n\n補足：切削後に完全焼結する。","source":"資料10 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p12","path":"assets/sourcepages/s10_p12.jpg"}]},{"id":"q135","number":135,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"半焼結ジルコニアを完全焼結する温度はどの程度か。","answer":"1,400〜1,600℃","explanation":"資料の記載：半焼結のジルコニアを切削→ 完全焼結（1,400～1,600℃）\n\n補足：高温焼結で最終強度を得る。","source":"資料10 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p12","path":"assets/sourcepages/s10_p12.jpg"}]},{"id":"q136","number":136,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"半焼結ジルコニアを完全焼結するときの焼結時収縮はどの程度か。","answer":"20％","explanation":"資料の記載：焼結時収縮20％← CADにより補正\n\n補足：CADで拡大補正して切削する。","source":"資料10 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p12","path":"assets/sourcepages/s10_p12.jpg"}]},{"id":"q137","number":137,"unit":"第4単元 ラミネートベニア・オールセラミック","importance":2,"type":"short","question":"焼結時収縮20％は、何によって補正するか。","answer":"CAD","explanation":"資料の記載：焼結時収縮20％← CADにより補正\n\n補足：収縮を見込んだ大きさで設計する。","source":"資料10 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p12","path":"assets/sourcepages/s10_p12.jpg"}]},{"id":"q138","number":138,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"歯科鋳造用合金のうち、金を主成分とする合金を何というか。","answer":"歯科鋳造用金合金","explanation":"資料の記載：１．歯科鋳造用金合金／２．歯科鋳造用金銀パラジウム合金\n\n補足：クラウンブリッジには主にタイプ3・4を用いる。","source":"資料11 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p3","path":"assets/sourcepages/s11_p3.jpg"}]},{"id":"q139","number":139,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"クラウンブリッジには主に何タイプを使用するか。","answer":"タイプ3・4","explanation":"資料の記載：クラウンブリッジには主にタイプ３,４を使用\n\n補足：強度と延びが固定性補綴に適する。","source":"資料11 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p3","path":"assets/sourcepages/s11_p3.jpg"}]},{"id":"q140","number":140,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":1,"type":"short","question":"歯科鋳造用合金のうち、金・銀・パラジウムを含む合金を何というか。","answer":"金銀パラジウム合金","explanation":"資料の記載：２．歯科鋳造用金銀パラジウム合金\n\n補足：日本で広く用いられてきた。","source":"資料11 p3","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p3","path":"assets/sourcepages/s11_p3.jpg"}]},{"id":"q141","number":141,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"歯科鋳造用合金のうち、銀を主成分とする合金を何というか。","answer":"歯科鋳造用銀合金","explanation":"資料の記載：３．歯科鋳造用銀合金／４．歯科鋳造用チタン合金\n\n補足：主にメタルコアやインレーに用いる。","source":"資料11 p4","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p4","path":"assets/sourcepages/s11_p4.jpg"}]},{"id":"q142","number":142,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"チタン合金の鋳造で推奨される埋没材は何系か。","answer":"マグネシア系埋没材","explanation":"資料の記載：埋没材：マグネシア系埋没材を推奨\n\n補足：チタンとの反応を抑える。","source":"資料11 p4","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p4","path":"assets/sourcepages/s11_p4.jpg"}]},{"id":"q143","number":143,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"金属の酸化を少なくして融解するため、火炎のどの部分を用いるか。","answer":"還元炎","explanation":"資料の記載：金属の酸化を少なくするために還元炎を用いる\n\n補足：溶解時に酸化を最小限にする。","source":"資料11 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p5","path":"assets/sourcepages/s11_p5.jpg"}]},{"id":"q144","number":144,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"都市ガスと空気を用いた火炎の融解最高温度は約何℃か。","answer":"約1,100℃","explanation":"資料の記載：融解最高温度：都市ガス＋空気→ 約1,100℃\n\n補足：低融点合金の溶解に用いる。","source":"資料11 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p5","path":"assets/sourcepages/s11_p5.jpg"}]},{"id":"q145","number":145,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"都市ガスと酸素を用いた火炎の融解最高温度は約何℃か。","answer":"約1,700℃","explanation":"資料の記載：都市ガス＋酸素→ 約1,700℃\n\n補足：より高温の溶解が可能。","source":"資料11 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p5","path":"assets/sourcepages/s11_p5.jpg"}]},{"id":"q146","number":146,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"大気に触れずにチタン合金を鋳造できる融解法は何か。","answer":"アルゴンアーク融解","explanation":"資料の記載：＊アルゴンアーク融解では大気に触れずにチタン合金の鋳造が可能\n\n補足：不活性雰囲気で酸化を防ぐ。","source":"資料11 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p5","path":"assets/sourcepages/s11_p5.jpg"}]},{"id":"q147","number":147,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"金属融解時に酸化物を除去し、溶融金属を保護する溶剤を何というか。","answer":"フラックス","explanation":"資料の記載：溶剤（フラックス）／＊金合金，金銀パラジウム合金では主にホウ砂を使用\n\n補足：金合金などではホウ砂を用いる。","source":"資料11 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p5","path":"assets/sourcepages/s11_p5.jpg"}]},{"id":"q148","number":148,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"金合金・金銀パラジウム合金の融解で主に用いるフラックスは何か。","answer":"ホウ砂","explanation":"資料の記載：＊金合金，金銀パラジウム合金では主にホウ砂を使用\n\n補足：酸化防止と酸化物吸着に働く。","source":"資料11 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p5","path":"assets/sourcepages/s11_p5.jpg"}]},{"id":"q149","number":149,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"鋳造機を回転させた遠心力で溶融金属を鋳型へ流入させる鋳造法を何というか。","answer":"遠心鋳造法","explanation":"資料の記載：１．遠心鋳造法／２．吸引加圧鋳造法：最も理想的な鋳造法\n\n補足：遠心力を鋳造圧として利用する。","source":"資料11 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p6","path":"assets/sourcepages/s11_p6.jpg"}]},{"id":"q150","number":150,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"鋳型内を吸引し、外側から加圧して溶融金属を流入させる最も理想的な鋳造法を何というか。","answer":"吸引加圧鋳造法","explanation":"資料の記載：２．吸引加圧鋳造法：最も理想的な鋳造法\n\n補足：最も理想的な鋳造法とされる。","source":"資料11 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p6","path":"assets/sourcepages/s11_p6.jpg"}]},{"id":"q151","number":151,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"鋳造体の内外に生じる微細な気泡に関する鋳造欠陥は何か。","answer":"鋳巣・気孔","explanation":"資料の記載：1．鋳巣，気孔／鋳造体の内外に生じる微細な気泡→引け巣，ブローホール\n\n補足：引け巣やブローホールを含む。","source":"資料11 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p7","path":"assets/sourcepages/s11_p7.jpg"}]},{"id":"q152","number":152,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"鋳造体の内外に生じる微細な気泡状欠陥のうち、凝固収縮に関係するものは何か。","answer":"引け巣","explanation":"資料の記載：鋳造体の内外に生じる微細な気泡→ 引け巣，ブローホール\n\n補足：湯だまりや適切なスプルー径で防ぐ。","source":"資料11 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p7","path":"assets/sourcepages/s11_p7.jpg"}]},{"id":"q153","number":153,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"鋳造体の内外に生じる微細な気泡状欠陥のうち、ガスに関係するものは何か。","answer":"ブローホール","explanation":"資料の記載：鋳造体の内外に生じる微細な気泡→ 引け巣，ブローホール\n\n補足：真空融解や還元雰囲気で防ぐ。","source":"資料11 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p7","path":"assets/sourcepages/s11_p7.jpg"}]},{"id":"q154","number":154,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"溶融金属と埋没材の間に空気が残留し、鋳造体に凹みを生じる欠陥を何というか。","answer":"背圧多孔","explanation":"資料の記載：２．背圧多孔／溶融金属と埋没材の間に空気残留→ 鋳造体の凹み\n\n補足：エアベントで防止する。","source":"資料11 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p7","path":"assets/sourcepages/s11_p7.jpg"}]},{"id":"q155","number":155,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"溶融金属の流れが合流した部分で、鋳造体表面に境目を生じる欠陥を何というか。","answer":"湯ざかい","explanation":"資料の記載：３．湯ざかい／鋳造体の表面に境目が生じる欠陥\n\n補足：酸化や不適切なスプルーイングが関与する。","source":"資料11 p7","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p7","path":"assets/sourcepages/s11_p7.jpg"}]},{"id":"q156","number":156,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"鋳造体の表面に突起物がついたものを何というか。","answer":"突起・鋳バリ","explanation":"資料の記載：4．突起，鋳バリ／鋳造体の表面に突起物がついたもの\n\n補足：埋没材の亀裂や気泡で生じる。","source":"資料11 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p8","path":"assets/sourcepages/s11_p8.jpg"}]},{"id":"q157","number":157,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"鋳造体の表面が粗造になった状態を何というか。","answer":"鋳肌荒れ・焼き付き","explanation":"資料の記載：5．鋳肌荒れ，焼き付き／鋳造体の表面が粗造になった状態\n\n補足：埋没材の過熱や金属融解条件が関与する。","source":"資料11 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p8","path":"assets/sourcepages/s11_p8.jpg"}]},{"id":"q158","number":158,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"鋳造後、鋳造リングを冷却するときに行う操作を何というか。","answer":"徐冷","explanation":"資料の記載：１．リングの徐冷と鋳造体の取り出し\n\n補足：急冷するとひずみやひび割れが増える。","source":"資料11 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p10","path":"assets/sourcepages/s11_p10.jpg"}]},{"id":"q159","number":159,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"金合金の酸洗いに用いる酸は何か。","answer":"希塩酸","explanation":"資料の記載：：希塩酸／金銀パラジウム合金：希硫酸など\n\n補足：埋没材除去後に酸浴を行う。","source":"資料11 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p10","path":"assets/sourcepages/s11_p10.jpg"}]},{"id":"q160","number":160,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"金銀パラジウム合金の酸洗いに用いる酸は何か。","answer":"希硫酸","explanation":"資料の記載：金銀パラジウム合金：希硫酸など\n\n補足：酸浴後は流水洗浄する。","source":"資料11 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p10","path":"assets/sourcepages/s11_p10.jpg"}]},{"id":"q161","number":161,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"金合金などを700〜800℃で溶体化処理した後、水中で急冷する熱処理を何というか。","answer":"軟化熱処理","explanation":"資料の記載：軟化熱処理：溶体化処理（700～800℃）後，水中で急冷\n\n補足：溶体化処理ともいう。","source":"資料11 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p10","path":"assets/sourcepages/s11_p10.jpg"}]},{"id":"q162","number":162,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"金合金などを350〜400℃で10〜30分係留した後、徐冷する熱処理を何というか。","answer":"硬化熱処理","explanation":"資料の記載：硬化熱処理：350～400℃で10～30分係留後，徐冷\n\n補足：時効硬化により強度を高める。","source":"資料11 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p10","path":"assets/sourcepages/s11_p10.jpg"}]},{"id":"q163","number":163,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"クラウン内面の適合を確認するため、必要に応じて用いる材料は何か。","answer":"シリコーンゴム適合試験材","explanation":"資料の記載：必要に応じてシリコーンゴム適合試験材を用いて内面の適合確認\n\n補足：内面の干渉部位を確認する。","source":"資料11 p11","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p11","path":"assets/sourcepages/s11_p11.jpg"}]},{"id":"q164","number":164,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"クラウンの隣接面接触関係を確認する際、デンタルフロスや咬合紙とともに用いる器具は何か。","answer":"コンタクトゲージ","explanation":"資料の記載：コンタクトゲージ，デンタルフロス，咬合紙を用いて確認\n\n補足：デンタルフロスや咬合紙も用いる。","source":"資料11 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p12","path":"assets/sourcepages/s11_p12.jpg"}]},{"id":"q165","number":165,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"クラウンの隣接面接触関係を調整するとき、歯間離開度はどの範囲にするか。","answer":"50〜110μm","explanation":"資料の記載：歯間離開度が50～110µmになるように\n\n補足：強すぎず弱すぎない接触へ調整する。","source":"資料11 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p12","path":"assets/sourcepages/s11_p12.jpg"}]},{"id":"q166","number":166,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"クラウン辺縁の適合は、視診の後に何を用いて確認するか。","answer":"探針","explanation":"資料の記載：視診により点検した後に，探針を用いて確認\n\n補足：視診後に段差や隙間を確認する。","source":"資料11 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p12","path":"assets/sourcepages/s11_p12.jpg"}]},{"id":"q167","number":167,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"鋳造体の研磨法のうち、最も一般的な方法は何か。","answer":"機械的研磨法","explanation":"資料の記載：１．機械的研磨法：最も一般的\n\n補足：荒研磨・仕上げ・艶出しの順に行う。","source":"資料11 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p13","path":"assets/sourcepages/s11_p13.jpg"}]},{"id":"q168","number":168,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"鋳造体の機械的研磨で、サンドペーパーポイントとともに用いる茶色の研磨器材は何か。","answer":"シリコーンポイント","explanation":"資料の記載：使用研磨用具：サンドペーパーポイント, シリコーンポイント(茶)\n\n補足：サンドペーパーポイントも用いる。","source":"資料11 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p13","path":"assets/sourcepages/s11_p13.jpg"}]},{"id":"q169","number":169,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"鋳造体の機械的研磨で用いる茶色のシリコーン製ポイントを何というか。","answer":"シリコーンポイント","explanation":"資料の記載：使用研磨用具：サンドペーパーポイント, シリコーンポイント(茶)\n\n補足：より細かい粒度で表面を滑沢にする。","source":"資料11 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p13","path":"assets/sourcepages/s11_p13.jpg"}]},{"id":"q170","number":170,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"鋳造体の仕上げ研磨で、チャモイスホイールとともに用いる研磨材は何か。","answer":"ルージュ","explanation":"資料の記載：使用研磨用具：チャモイスホイール＋ルージュ\n\n補足：チャモイスホイールと併用する。","source":"資料11 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p13","path":"assets/sourcepages/s11_p13.jpg"}]},{"id":"q171","number":171,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"電解液中で通電し、金属表面層を溶解させる研磨法を何というか。","answer":"電解研磨法","explanation":"資料の記載：２．電解研磨法／電解液中で通電することにより表面層が溶解\n\n補足：表面層を選択的に溶解する。","source":"資料11 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p13","path":"assets/sourcepages/s11_p13.jpg"}]},{"id":"q172","number":172,"unit":"第5単元 鋳造・鋳造欠陥・試適・研磨","importance":2,"type":"short","question":"強酸などを用いて金属表面を研磨する方法を何というか。","answer":"化学研磨法","explanation":"資料の記載：３．化学研磨法／強酸などを用いて\n\n補足：化学反応で表面を平滑化する。","source":"資料11 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p13","path":"assets/sourcepages/s11_p13.jpg"}]},{"id":"q173","number":173,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"クラウンを確認のため一時的に装着することを何というか。","answer":"仮着","explanation":"資料の記載：仮着：確認のための一時装着\n\n補足：機能・清掃性・審美性などを経過観察する。","source":"資料12 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p5","path":"assets/sourcepages/s12_p5.jpg"}]},{"id":"q174","number":174,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"クラウンの試適後、口腔内へ最終的に装着する操作を何というか。","answer":"合着・接着","explanation":"資料の記載：合着（接着）／試適〜合着（臨床例）\n\n補足：問題がなければ仮着せず行う場合もある。","source":"資料12 p6","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p6","path":"assets/sourcepages/s12_p6.jpg"}]},{"id":"q175","number":175,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"最終装着前に、クラウンを一定期間一時的に装着する操作を何というか。","answer":"仮着","explanation":"資料の記載：仮着：確認のための一時装着\n\n補足：長期予後に不安がある場合に経過観察する。","source":"資料12 p5","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p5","path":"assets/sourcepages/s12_p5.jpg"}]},{"id":"q176","number":176,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"仮着セメントには、必要期間脱離しない接着力をもちながら、除去は容易にできる何が求められるか。","answer":"相反する性質","explanation":"資料の記載：除去は容易にできる相反する性質が要求される\n\n補足：必要期間は脱離せず、撤去時は容易である必要がある。","source":"資料12 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p8","path":"assets/sourcepages/s12_p8.jpg"}]},{"id":"q177","number":177,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"カルボキシ基が歯質のCaとキレート結合するセメントは何か。","answer":"ポリカルボキシレートセメント","explanation":"資料の記載：ポリカルボキシレートセメント／カルボキシ基がCaとキレート結合\n\n補足：キレート結合により歯質へ結合する。","source":"資料12 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p8","path":"assets/sourcepages/s12_p8.jpg"}]},{"id":"q178","number":178,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"鎮静・消炎作用を有し、仮着に用いられるセメントは何か。","answer":"酸化亜鉛ユージノールセメント","explanation":"資料の記載：酸化亜鉛ユージノールセメント／鎮静・消炎作用→ 仮着用\n\n補足：生活歯の仮着に用いられる。","source":"資料12 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p8","path":"assets/sourcepages/s12_p8.jpg"}]},{"id":"q179","number":179,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"酸化亜鉛ユージノールセメントの成分のうち、レジンの重合を阻害するものは何か。","answer":"ユージノール","explanation":"資料の記載：ユージノールがレジン重合阻害\n\n補足：ラジカルを失活させる。","source":"資料12 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p8","path":"assets/sourcepages/s12_p8.jpg"}]},{"id":"q180","number":180,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"レジンの重合を阻害しない仮着用セメントは何系か。","answer":"非ユージノール系","explanation":"資料の記載：非ユージノール系／レジン重合阻害なし\n\n補足：接着性レジンセメント予定時に選択する。","source":"資料12 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p8","path":"assets/sourcepages/s12_p8.jpg"}]},{"id":"q181","number":181,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"維持力と封鎖性が高い仮着用セメントは何系か。","answer":"レジン系","explanation":"資料の記載：レジン系／維持力・封鎖性が高い基本的に接着機能はない（接着性モ\n\n補足：封鎖性も高い。","source":"資料12 p8","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p8","path":"assets/sourcepages/s12_p8.jpg"}]},{"id":"q182","number":182,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"歯冠補綴装置の最終装着に用いるセメントが具備すべき要件を、何用セメントの要件というか。","answer":"合着","explanation":"資料の記載：合着用セメントが具備すべき要件\n\n補足：リン酸亜鉛セメントが代表。","source":"資料12 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p10","path":"assets/sourcepages/s12_p10.jpg"}]},{"id":"q183","number":183,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"被着体表面の微細な凹凸への嵌合効力や、分子間の結合によって被着体同士を結び付けることを何というか。","answer":"接着","explanation":"資料の記載：「接着」：被着体表面の微細な凹凸に入り込んだ嵌合効力、\n\n補足：被着体とセメントの化学結合を含む。","source":"資料12 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p10","path":"assets/sourcepages/s12_p10.jpg"}]},{"id":"q184","number":184,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"リン酸亜鉛セメントが歯冠補綴装置を維持する嵌合効力を何というか。","answer":"アンカー効果","explanation":"資料の記載：例）リン酸亜鉛セメントは嵌合効力（アンカー効果）のみで歯冠補綴装置を維持\n\n補足：機械的結合の一種。","source":"資料12 p10","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p10","path":"assets/sourcepages/s12_p10.jpg"}]},{"id":"q185","number":185,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"ファンデルワールス力による接着の結合様式を何というか。","answer":"物理的結合","explanation":"資料の記載：物理的結合／（ファンデルワールス力）\n\n補足：ファンデルワールス力が代表。","source":"資料12 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p12","path":"assets/sourcepages/s12_p12.jpg"}]},{"id":"q186","number":186,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"共有結合や水素結合による接着の結合様式を何というか。","answer":"化学的結合","explanation":"資料の記載：化学的結合（共有、水素結合）\n\n補足：被着体と接着剤間の結合。","source":"資料12 p12","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p12","path":"assets/sourcepages/s12_p12.jpg"}]},{"id":"q187","number":187,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"接着性はなく、嵌合効力のみで維持する合着用セメントは何か。","answer":"リン酸亜鉛セメント","explanation":"資料の記載：リン酸亜鉛セメント／嵌合効力のみ（接着なし）\n\n補足：酸化亜鉛とリン酸の酸塩基反応で硬化する。","source":"資料12 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p13","path":"assets/sourcepages/s12_p13.jpg"}]},{"id":"q188","number":188,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"歯質と化学的に結合する従来型のグラスアイオノマー系セメントを何というか。","answer":"グラスアイオノマーセメント","explanation":"資料の記載：グラスアイオノマーセメント／セメントの種類（P315-319）\n\n補足：ガラスから溶出したイオンで架橋する。","source":"資料12 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p13","path":"assets/sourcepages/s12_p13.jpg"}]},{"id":"q189","number":189,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"レジンの重合反応と酸塩基反応の両方で硬化するセメントは何か。","answer":"レジン添加型GIC","explanation":"資料の記載：レジン添加型GIC／重合＋酸塩基反応\n\n補足：グラスアイオノマーへレジン成分を添加したもの。","source":"資料12 p13","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p13","path":"assets/sourcepages/s12_p13.jpg"}]},{"id":"q190","number":190,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"4-META系レジンセメントは、何系レジンセメントか。","answer":"MMA系レジンセメント","explanation":"資料の記載：4-META系レジンセメント\n\n補足：TBBを重合開始剤に用いる。","source":"資料12 p23","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p23","path":"assets/sourcepages/s12_p23.jpg"}]},{"id":"q191","number":191,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"歯面処理やプライマー処理を必要としないレジンセメントを何というか。","answer":"セルフアドヒーシブ型レジンセメント","explanation":"資料の記載：接着性モノマー（補足）\n\n補足：セルフエッチング機構を組み込む。","source":"資料12 p17","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p17","path":"assets/sourcepages/s12_p17.jpg"}]},{"id":"q192","number":192,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"グラスアイオノマーセメントの硬化反応で、ガラスを溶解する成分は何か。","answer":"酸","explanation":"資料の記載：酸がガラスを溶解し、\n\n補足：イオンを溶出させ硬化反応を開始する。","source":"資料12 p14","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p14","path":"assets/sourcepages/s12_p14.jpg"}]},{"id":"q193","number":193,"unit":"第6単元 仮着・合着・接着","importance":1,"type":"short","question":"イオン架橋を作るイオンは何か。","answer":"Ca2+・Al2+","explanation":"資料の記載：Ca2+・Al2+によるイオン架橋\n\n補足：ポリ酸のカルボキシ基間を架橋する。","source":"資料12 p14","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p14","path":"assets/sourcepages/s12_p14.jpg"}]},{"id":"q194","number":194,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"レジンセメントで、光照射と化学重合の両方で硬化する方式を何というか。","answer":"デュアルキュア","explanation":"資料の記載：デュアルキュア系が基本／レジンセメントは\n\n補足：光重合と化学重合を併用する。","source":"資料12 p15","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p15","path":"assets/sourcepages/s12_p15.jpg"}]},{"id":"q195","number":195,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"レジンセメントの接着で、歯質とレジンを橋渡しする成分を何というか。","answer":"接着性モノマー","explanation":"資料の記載：接着性モノマーが橋渡しとなり、\n\n補足：被着体と化学的に結合する。","source":"資料12 p15","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p15","path":"assets/sourcepages/s12_p15.jpg"}]},{"id":"q196","number":196,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"エナメル質の重量のうち、ハイドロキシアパタイトが占める割合は約何％か。","answer":"約96％","explanation":"資料の記載：エナメル質は約96%がハイドロキシアパタイト\n\n補足：主成分はハイドロキシアパタイト。","source":"資料12 p18","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p18","path":"assets/sourcepages/s12_p18.jpg"}]},{"id":"q197","number":197,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"エナメル質のエッチングには、何％のリン酸を用いるか。","answer":"30〜40％","explanation":"資料の記載：30〜40%リン酸でエッチングすると表面が脱灰し、\n\n補足：表面を脱灰して微細な凹凸を作る。","source":"資料12 p18","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p18","path":"assets/sourcepages/s12_p18.jpg"}]},{"id":"q198","number":198,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"リン酸エッチングによってエナメル質表面に形成される微細な凹凸を何というか。","answer":"マイクロポア","explanation":"資料の記載：微細な凹凸（マイクロポア）が形成\n\n補足：レジンが流入する空間となる。","source":"資料12 p18","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p18","path":"assets/sourcepages/s12_p18.jpg"}]},{"id":"q199","number":199,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"エナメル質の微細な凹凸へレジンが流入・重合して形成されるものを何というか。","answer":"レジンタグ","explanation":"資料の記載：凹凸へレジンが流入・重合することでレジンタグが\n\n補足：強い機械的結合を形成する。","source":"資料12 p18","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p18","path":"assets/sourcepages/s12_p18.jpg"}]},{"id":"q200","number":200,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"レジンタグによって得られる強い機械的結合を何というか。","answer":"マイクロメカニカルロック","explanation":"資料の記載：形成され、強い機械的結合（マイクロメカニカル\n\n補足：エナメル質接着の主体。","source":"資料12 p18","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p18","path":"assets/sourcepages/s12_p18.jpg"}]},{"id":"q201","number":201,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"象牙質接着で、酸処理によって除去する切削屑の層を何というか。","answer":"スミヤー層","explanation":"資料の記載：スミヤー層除去、象牙質表面を脱灰\n\n補足：象牙質接着では除去または改質する。","source":"資料12 p20","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p20","path":"assets/sourcepages/s12_p20.jpg"}]},{"id":"q202","number":202,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"象牙質接着で、脱灰された象牙質へレジンが浸透して形成される層を何というか。","answer":"ハイブリッド層","explanation":"資料の記載：スミヤー層除去→ レジン浸透→ ハイブリッド層形成\n\n補足：象牙質接着の中心構造。","source":"資料12 p19","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p19","path":"assets/sourcepages/s12_p19.jpg"}]},{"id":"q203","number":203,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"象牙質接着法のうち、コラーゲンを除去してアパタイトを露出させる方法を何というか。","answer":"次亜塩素酸Naゲル法","explanation":"資料の記載：E：次亜塩素酸Naゲル法／A-Dと発想が逆！コラーゲン除去→ アパタイト露出\n\n補足：通常のハイブリッド層形成と逆の発想。","source":"資料12 p20","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p20","path":"assets/sourcepages/s12_p20.jpg"}]},{"id":"q204","number":204,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"次亜塩素酸ナトリウム処理後、残留NaOClを還元してレジン重合阻害を防止する薬剤は何か。","answer":"スルフィン酸塩","explanation":"資料の記載：C：スルフィン酸塩／残留NaOClを還元し、レジン重合阻害を防止（OCl⁻ 次亜塩素酸イオン）\n\n補足：残留NaOClを還元する。","source":"資料12 p20","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p20","path":"assets/sourcepages/s12_p20.jpg"}]},{"id":"q205","number":205,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"ジルコニア表面にシリカを付着させ、接着性を高める処理を何というか。","answer":"トライボケミカル処理","explanation":"資料の記載：トライボケミカル処理（P324）／ジルコニア接着\n\n補足：シリカ被覆アルミナ粒子を噴射する。","source":"資料12 p21","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p21","path":"assets/sourcepages/s12_p21.jpg"}]},{"id":"q206","number":206,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"トライボケミカル処理後、機械的嵌合に加えて有効となる表面処理は何か。","answer":"シラン処理","explanation":"資料の記載：機械的嵌合に加え、シラン処理が有効となり、\n\n補足：形成されたシリカ膜と反応する。","source":"資料12 p21","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p21","path":"assets/sourcepages/s12_p21.jpg"}]},{"id":"q207","number":207,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"クラウン接着操作で、仮着セメント除去後、シラン処理の前に行う処理は何か。","answer":"サンドブラスト","explanation":"資料の記載：A 仮着セメント除去→B サンドブラスト→C シラン処理\n\n補足：内面を粗造化して接着面積を増す。","source":"資料12 p22","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p22","path":"assets/sourcepages/s12_p22.jpg"}]},{"id":"q208","number":208,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"クラウン接着操作で、サンドブラストの後に行う処理は何か。","answer":"シラン処理","explanation":"資料の記載：A 仮着セメント除去→ B サンドブラスト→ C シラン処理\n\n補足：レジン系材料との化学結合を高める。","source":"資料12 p22","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p22","path":"assets/sourcepages/s12_p22.jpg"}]},{"id":"q209","number":209,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"クラウン接着操作で、余剰セメントを除去しやすくするために短時間光照射する操作を何というか。","answer":"タックキュア","explanation":"資料の記載：→ F タックキュア／G 余剰セメント除去→ H 最終重合\n\n補足：余剰セメント除去を容易にする。","source":"資料12 p22","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p22","path":"assets/sourcepages/s12_p22.jpg"}]},{"id":"q210","number":210,"unit":"第6単元 仮着・合着・接着","importance":2,"type":"short","question":"クラウン接着操作で、余剰セメント除去後に行う重合操作は何か。","answer":"最終重合","explanation":"資料の記載：G 余剰セメント除去→ H 最終重合\n\n補足：余剰セメント除去後に十分硬化させる。","source":"資料12 p22","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p22","path":"assets/sourcepages/s12_p22.jpg"}]},{"id":"q211","number":211,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"クラウンは形成面を確実に被覆し、歯髄の鎮静・保護や歯周組織の炎症を惹起しないように配慮する要件は何か。","answer":"生物学的要件","explanation":"資料の記載：クラウンは形成面を確実に被覆／支台歯形成からクラウン装着まで歯髄の鎮静・保護に配慮／歯周組織の炎症を惹起しないように歯冠形態に配慮／A．生物学的要件\n\n補足：支台歯・歯髄・歯周組織・軟組織などへの為害性を避ける要件。","source":"資料7 p3（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p3（赤字）","path":"assets/sourcepages/s7_p3.jpg"}]},{"id":"q212","number":212,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"力学的にバランスのとれた咬合接触に関する要件は何か。","answer":"機能的要件","explanation":"資料の記載：B．機能的要件／力学的にバランスのとれた咬合接触\n\n補足：補綴装置が口腔機能と調和するための要件。","source":"資料7 p4（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p4（赤字）","path":"assets/sourcepages/s7_p4.jpg"}]},{"id":"q213","number":213,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"加わる力によって脱離や破損が生じない構造、強度、耐摩耗性に関する要件は何か。","answer":"力学的要件","explanation":"資料の記載：C．力学的要件／加わる力によって脱離や破損が生じない構造，強度，耐摩耗性\n\n補足：変形・破折・脱離を防ぐための要件という意味である。","source":"資料7 p4（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p4（赤字）","path":"assets/sourcepages/s7_p4.jpg"}]},{"id":"q214","number":214,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"歯の形態、大きさ、排列、咬合、色調などを顎口腔系と調和させる要件は何か。","answer":"審美的要件","explanation":"資料の記載：D．審美的要件／歯の形態，大きさ，排列，咬合，色調などを顎口腔系と調和させる\n\n補足：外観や色調だけでなく、歯の形態・大きさ・排列・咬合も含む。","source":"資料7 p4（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p4（赤字）","path":"assets/sourcepages/s7_p4.jpg"}]},{"id":"q215","number":215,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"操作性に優れ、為害性がなく、物理的、化学的に安定した材料に関する要件は何か。","answer":"材料学的要件","explanation":"資料の記載：E．材料学的要件／操作性に優れ，為害性がなく，物理的，化学的に安定した材料\n\n補足：使用材料の性質や組合せを扱う要件である。","source":"資料7 p4（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p4（赤字）","path":"assets/sourcepages/s7_p4.jpg"}]},{"id":"q216","number":216,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"盛り上げ法によるワックスアップの実際として示されている全部被覆冠は何か。","answer":"全部金属冠","explanation":"資料の記載：１．全部金属冠／１）分離材の塗布\n\n補足：資料7では全部金属冠のワックスアップ手順が示されている。","source":"資料7 p10（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p10（赤字）","path":"assets/sourcepages/s7_p10.jpg"}]},{"id":"q217","number":217,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"石膏系埋没材を耐火材の種類で分類したとき、クリストバライトを用いるものを何というか。","answer":"クリストバライト埋没材","explanation":"資料の記載：耐火材の種類による分類：①クリストバライト埋没材\n\n補足：石膏系埋没材を耐火材の種類によって分類した名称。","source":"資料7 p15（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p15（赤字）","path":"assets/sourcepages/s7_p15.jpg"}]},{"id":"q218","number":218,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"石膏系埋没材を耐火材の種類で分類したとき、石英を用いるものを何というか。","answer":"石英埋没材","explanation":"資料の記載：②石英埋没材／埋没材の組成（P233）\n\n補足：石膏系埋没材を耐火材の種類によって分類した名称。","source":"資料7 p15（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p15（赤字）","path":"assets/sourcepages/s7_p15.jpg"}]},{"id":"q219","number":219,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"チタン合金の鋳造に用いる専用の埋没材を何というか。","answer":"チタン鋳造用埋没材","explanation":"資料の記載：チタン鋳造用埋没材／２）リン酸塩系埋没材（融点が1,000℃以上の）高溶金属用\n\n補足：チタンの鋳造には専用の埋没材を用いる。","source":"資料7 p15（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p15（赤字）","path":"assets/sourcepages/s7_p15.jpg"}]},{"id":"q220","number":220,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"クリストバライトと石英を含み、急速加熱して使用する埋没材を何というか。","answer":"急速加熱型埋没材","explanation":"資料の記載：急速加熱型埋没材（P235）／↑ クリストバライトと石英\n\n補足：クリストバライト埋没材にも石英埋没材にも分類されない。","source":"資料7 p16（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p16（赤字）","path":"assets/sourcepages/s7_p16.jpg"}]},{"id":"q221","number":221,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"キャスティングライナーは、何膨張と何膨張のために使用するか。","answer":"硬化膨張・加熱膨張","explanation":"資料の記載：キャスティングライナー for 硬化膨張 and 加熱膨張\n\n補足：埋没材の膨張によって金属の鋳造収縮を補償する。","source":"資料7 p17（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p17（赤字）","path":"assets/sourcepages/s7_p17.jpg"}]},{"id":"q222","number":222,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"ジャケットクラウンのうち、すべてセラミックで製作するものを何というか。","answer":"オールセラミッククラウン","explanation":"資料の記載：①オールセラミッククラウン：すべてセラミック\n\n補足：ジャケットクラウンの一種。","source":"資料8 p3（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p3（赤字）","path":"assets/sourcepages/s8_p3.jpg"}]},{"id":"q223","number":223,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"ジャケットクラウンのうち、すべてレジンで製作するものを何というか。","answer":"ハイブリッド型コンポジットレジンクラウン","explanation":"資料の記載：②ハイブリッド型コンポジットレジンクラウン：すべてレジン\n\n補足：資料ではレジンジャケットクラウンを含むとされる。","source":"資料8 p3（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p3（赤字）","path":"assets/sourcepages/s8_p3.jpg"}]},{"id":"q224","number":224,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"ジャケットクラウンの種類のうち、レジン製のものを何というか。","answer":"レジンジャケットクラウン","explanation":"資料の記載：（レジンジャケットクラウンを含む）／③PEEK冠：すべてPEEK（ポリエーテルエーテルケトン）\n\n補足：ハイブリッド型コンポジットレジンクラウンに含まれる。","source":"資料8 p3（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p3（赤字）","path":"assets/sourcepages/s8_p3.jpg"}]},{"id":"q225","number":225,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"ジャケットクラウンのうち、すべてPEEKで製作するものを何というか。","answer":"PEEK冠","explanation":"資料の記載：③PEEK冠：すべてPEEK（ポリエーテルエーテルケトン）\n\n補足：PEEKはポリエーテルエーテルケトンの略称。","source":"資料8 p3（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p3（赤字）","path":"assets/sourcepages/s8_p3.jpg"}]},{"id":"q226","number":226,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"CAD/CAM冠の支台歯形成で、グルーブやキャビティなどの形態を総称して何というか。","answer":"補助的保持形態","explanation":"資料の記載：補助的保持形態（グルーブやキャビティなど）は基本的に付与しない\n\n補足：グルーブやキャビティなどは、スキャン時や加工時の精度に影響するため基本的に付与しない。","source":"資料8 p5（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p5（赤字）","path":"assets/sourcepages/s8_p5.jpg"}]},{"id":"q227","number":227,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"オールセラミッククラウンの支台歯形成で、ディープシャンファーのほかに用いるフィニッシュラインは何か。","answer":"ラウンデッドショルダー","explanation":"資料の記載：全周ディープシャンファーor ラウンデッドショルダー\n\n補足：幅は1.0〜1.2mmとされる。","source":"資料8 p5（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p5（赤字）","path":"assets/sourcepages/s8_p5.jpg"}]},{"id":"q228","number":228,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"ハイブリッド型コンポジットレジンクラウンは、陶材と比べて技工操作が容易で費用面ではどのような特徴があるか。","answer":"低コスト","explanation":"資料の記載：点：①陶材よりも技工操作が容易で低コスト\n\n補足：ハイブリッド型コンポジットレジンクラウンの利点。","source":"資料8 p7（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p7（赤字）","path":"assets/sourcepages/s8_p7.jpg"}]},{"id":"q229","number":229,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"ハイブリッド型コンポジットレジンクラウンは、陶材と比べて色調安定性にどのような欠点があるか。","answer":"変色しやすい","explanation":"資料の記載：陶材よりも変色しやすく，光沢が消失しやすい\n\n補足：光沢も消失しやすい。","source":"資料8 p7（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p7（赤字）","path":"assets/sourcepages/s8_p7.jpg"}]},{"id":"q230","number":230,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"ハイブリッド型コンポジットレジンクラウンは吸水性があるため、何が付着しやすいか。","answer":"プラーク付着性","explanation":"資料の記載：吸水性があるためプラーク付着性あり，生体親和性劣る\n\n補足：生体親和性も劣る。","source":"資料8 p7（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p7（赤字）","path":"assets/sourcepages/s8_p7.jpg"}]},{"id":"q231","number":231,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"ハイブリッド型コンポジットレジンクラウンの装着に必須のセメントは何か。","answer":"接着性レジンセメント","explanation":"資料の記載：③接着性レジンセメントの使用が必須\n\n補足：資料に「使用が必須」と明記されている。","source":"資料8 p7（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料8 p7（赤字）","path":"assets/sourcepages/s8_p7.jpg"}]},{"id":"q232","number":232,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"前装冠のうち、前装部が陶材であるものを何というか。","answer":"陶材焼付冠","explanation":"資料の記載：陶材焼付冠／：前装部が陶材\n\n補足：前装冠は外観に触れる部分を歯冠色材料に置き換えた金属冠。","source":"資料9 p3（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p3（赤字）","path":"assets/sourcepages/s9_p3.jpg"}]},{"id":"q233","number":233,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"前装冠のうち、前装部がレジンであるものを何というか。","answer":"レジン前装冠","explanation":"資料の記載：レジン前装冠：前装部がレジン\n\n補足：前装冠は外観に触れる部分を歯冠色材料に置き換えた金属冠。","source":"資料9 p3（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p3（赤字）","path":"assets/sourcepages/s9_p3.jpg"}]},{"id":"q234","number":234,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"レジン前装冠は、陶材焼付冠と比べて使用器材や設備の費用にどのような特徴があるか。","answer":"安価","explanation":"資料の記載：②使用器材や設備が安価\n\n補足：陶材焼付冠と比較した利点。","source":"資料9 p4（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p4（赤字）","path":"assets/sourcepages/s9_p4.jpg"}]},{"id":"q235","number":235,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"レジン前装冠で経時的に生じることがある色調変化を何というか。","answer":"変色","explanation":"資料の記載：③経時的に変色することがある\n\n補足：資料では「経時的に変色することがある」と示されている。","source":"資料9 p4（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p4（赤字）","path":"assets/sourcepages/s9_p4.jpg"}]},{"id":"q236","number":236,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"レジン前装冠で、レジンの機械的維持に用いる球状の維持装置を何というか。","answer":"リテンションビーズ","explanation":"資料の記載：リテンションビーズなど／（粒径：0.15～0.2mm）\n\n補足：粒径は0.15〜0.2mm。","source":"資料9 p9（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p9（赤字）","path":"assets/sourcepages/s9_p9.jpg"}]},{"id":"q237","number":237,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"レジン前装冠の金属前装面に行う、アルミナ粒子を用いた表面処理を何というか。","answer":"アルミナサンドブラスト処理","explanation":"資料の記載：アルミナサンドブラスト処理\n\n補足：金属表面を粗造化し、接着を得る。","source":"資料9 p23（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p23（赤字）","path":"assets/sourcepages/s9_p23.jpg"}]},{"id":"q238","number":238,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"陶材焼付冠の陶材は、約何℃の焼成温度から室温まで徐冷すると熱収縮するか。","answer":"950℃","explanation":"資料の記載：焼成温度（約950℃）から室温まで徐冷する際に熱収縮（約0.6～0.8％）\n\n補足：資料末尾の国試問題でも問われている。","source":"資料9 p14（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p14（赤字）","path":"assets/sourcepages/s9_p14.jpg"}]},{"id":"q239","number":239,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"金属と陶材の機械的結合で、金属表面の微細な凹凸に陶材が入り込む効果を何というか。","answer":"嵌合効果","explanation":"資料の記載：嵌合効果：金属表面の微細な凹凸に陶材が嵌入\n\n補足：陶材と金属の機械的結合。","source":"資料9 p15（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p15（赤字）","path":"assets/sourcepages/s9_p15.jpg"}]},{"id":"q240","number":240,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"陶材焼付前に行うガス抜きを何というか。","answer":"ディギャッシング","explanation":"資料の記載：５）ディギャッシング（ガス抜き）\n\n補足：金属表面の酸化膜形成にも関係する。","source":"資料9 p19（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p19（赤字）","path":"assets/sourcepages/s9_p19.jpg"}]},{"id":"q241","number":241,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"ラミネートベニアを歯の唇面へ接着する際に用いるセメントは何か。","answer":"接着性レジンセメント","explanation":"資料の記載：→接着性レジンセメントによって唇面に接着\n\n補足：資料に示された装着材料。","source":"資料10 p3（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p3（赤字）","path":"assets/sourcepages/s10_p3.jpg"}]},{"id":"q242","number":242,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"歯質削除を最小限にする「ミニマルインターベンション」の略称は何か。","answer":"MI","explanation":"資料の記載：（MI：ミニマルインターベンション）\n\n補足：MIはミニマルインターベンション。","source":"資料10 p3（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p3（赤字）","path":"assets/sourcepages/s10_p3.jpg"}]},{"id":"q243","number":243,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"耐火模型上でセラミックスを築盛・焼成するオールセラミッククラウンの製作法を何というか。","answer":"耐火模型法","explanation":"資料の記載：１．耐火模型法／耐火模型上でセラミックスを築盛，焼成する方法\n\n補足：現在は主にラミネートベニアの製作に用いる。","source":"資料10 p10（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p10（赤字）","path":"assets/sourcepages/s10_p10.jpg"}]},{"id":"q244","number":244,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"鋳型に高温で可塑化したセラミックインゴットをプレス成形する製作法を何というか。","answer":"ロストワックス法","explanation":"資料の記載：２．ロストワックス法／鋳型に高温で可塑化したインゴットをプレス成形\n\n補足：ワックスパターンを用いて鋳型を作る。","source":"資料10 p10（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p10（赤字）","path":"assets/sourcepages/s10_p10.jpg"}]},{"id":"q245","number":245,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"ステイン用陶材を表面に塗布して歯冠色を再現する方法を何というか。","answer":"ステイニング","explanation":"資料の記載：ステイニング：ステイン用陶材を塗布して歯冠色の再現\n\n補足：ロストワックス法によるセラミック製作の色調再現法。","source":"資料10 p10（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p10（赤字）","path":"assets/sourcepages/s10_p10.jpg"}]},{"id":"q246","number":246,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"現在、オールセラミッククラウンの製作で最も多く用いられている方法は何か。","answer":"CAD/CAM法","explanation":"資料の記載：３．CAD/CAM法／現在，最も多く用いられている方法\n\n補足：現在、最も多く用いられている方法。","source":"資料10 p11（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p11（赤字）","path":"assets/sourcepages/s10_p11.jpg"}]},{"id":"q247","number":247,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"ジルコニアのうち、コーピングに応用される正方晶ジルコニア多結晶体の略称は何か。","answer":"TZP","explanation":"資料の記載：正方晶ジルコニア多結晶体（TZP）：コーピングに応用\n\n補足：正方晶ジルコニア多結晶体。","source":"資料10 p9（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p9（赤字）","path":"assets/sourcepages/s10_p9.jpg"}]},{"id":"q248","number":248,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"ジルコニアのうち、モノリシッククラウンに応用される部分安定化ジルコニアの略称は何か。","answer":"PSZ","explanation":"資料の記載：部分安定化ジルコニア（PSZ）：モノリシッククラウンに応用\n\n補足：部分安定化ジルコニア。","source":"資料10 p9（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料10 p9（赤字）","path":"assets/sourcepages/s10_p9.jpg"}]},{"id":"q249","number":249,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"クラウン治療の流れで、研磨の前に行う技工操作は何か。","answer":"鋳造","explanation":"資料の記載：鋳造，研磨／クラウンの試適，調整，研磨，装着\n\n補足：資料11の講義内容。","source":"資料11 p2（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p2（赤字）","path":"assets/sourcepages/s11_p2.jpg"}]},{"id":"q250","number":250,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"クラウン治療の流れで、鋳造の後に行う技工操作は何か。","answer":"研磨","explanation":"資料の記載：クラウンの試適，調整，研磨，装着\n\n補足：資料11の講義内容。","source":"資料11 p2（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p2（赤字）","path":"assets/sourcepages/s11_p2.jpg"}]},{"id":"q251","number":251,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"金属の酸化を少なくして融解するため、火炎のどの部分を用いるか。","answer":"還元炎","explanation":"資料の記載：金属の酸化を少なくするために還元炎を用いる\n\n補足：金属溶解時の注意事項。","source":"資料11 p5（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p5（赤字）","path":"assets/sourcepages/s11_p5.jpg"}]},{"id":"q252","number":252,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"金合金・金銀パラジウム合金の融解で主に用いるフラックスは何か。","answer":"ホウ砂","explanation":"資料の記載：＊金合金，金銀パラジウム合金では主にホウ砂を使用\n\n補足：酸化防止と酸化物の吸着に用いる。","source":"資料11 p5（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p5（赤字）","path":"assets/sourcepages/s11_p5.jpg"}]},{"id":"q253","number":253,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"鋳造機を回転させた遠心力で溶融金属を鋳型へ流入させる鋳造法を何というか。","answer":"遠心鋳造法","explanation":"資料の記載：１．遠心鋳造法／２．吸引加圧鋳造法：最も理想的な鋳造法\n\n補足：鋳造法の一つ。","source":"資料11 p6（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p6（赤字）","path":"assets/sourcepages/s11_p6.jpg"}]},{"id":"q254","number":254,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"鋳型内を吸引し、外側から加圧して溶融金属を流入させる最も理想的な鋳造法を何というか。","answer":"吸引加圧鋳造法","explanation":"資料の記載：２．吸引加圧鋳造法：最も理想的な鋳造法\n\n補足：資料では「最も理想的な鋳造法」と示されている。","source":"資料11 p6（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p6（赤字）","path":"assets/sourcepages/s11_p6.jpg"}]},{"id":"q255","number":255,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"鋳造体の内外に生じる微細な気泡状欠陥のうち、凝固収縮に関係するものは何か。","answer":"引け巣","explanation":"資料の記載：鋳造体の内外に生じる微細な気泡→ 引け巣，ブローホール\n\n補足：鋳巣・気孔に含まれる鋳造欠陥。","source":"資料11 p7（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p7（赤字）","path":"assets/sourcepages/s11_p7.jpg"}]},{"id":"q256","number":256,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"鋳造体の内外に生じる微細な気泡状欠陥のうち、ガスに関係するものは何か。","answer":"ブローホール","explanation":"資料の記載：鋳造体の内外に生じる微細な気泡→ 引け巣，ブローホール\n\n補足：鋳巣・気孔に含まれる鋳造欠陥。","source":"資料11 p7（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p7（赤字）","path":"assets/sourcepages/s11_p7.jpg"}]},{"id":"q257","number":257,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"溶融金属と埋没材の間に空気が残留し、鋳造体に凹みを生じる欠陥を何というか。","answer":"背圧多孔","explanation":"資料の記載：２．背圧多孔／溶融金属と埋没材の間に空気残留→ 鋳造体の凹み\n\n補足：対策はエアベント。","source":"資料11 p7（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p7（赤字）","path":"assets/sourcepages/s11_p7.jpg"}]},{"id":"q258","number":258,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"溶融金属の流れが合流した部分で、鋳造体表面に境目を生じる欠陥を何というか。","answer":"湯ざかい","explanation":"資料の記載：３．湯ざかい／鋳造体の表面に境目が生じる欠陥\n\n補足：酸化させない加熱と適切なスプルーイングが対策。","source":"資料11 p7（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p7（赤字）","path":"assets/sourcepages/s11_p7.jpg"}]},{"id":"q259","number":259,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"鋳造体表面に突起物が生じた鋳造欠陥を何というか。","answer":"突起","explanation":"資料の記載：鋳造体の表面に突起物がついたもの\n\n補足：埋没操作時の気泡混入などが原因。","source":"資料11 p8（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p8（赤字）","path":"assets/sourcepages/s11_p8.jpg"}]},{"id":"q260","number":260,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"リングの落下、埋没材の急速加熱や過熱によるひび割れ、埋没操作時の気泡混入で生じる鋳造欠陥は何か。","answer":"突起・鋳バリ","explanation":"資料の記載：4．突起，鋳バリ／原因：リングの落下，埋没材の急速加熱や過熱によるひび割れ，埋没操作時の気泡混入\n\n補足：埋没材の急速加熱や過熱などが原因。","source":"資料11 p8（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p8（赤字）","path":"assets/sourcepages/s11_p8.jpg"}]},{"id":"q261","number":261,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"鋳造体の表面が粗造になった状態を何というか。","answer":"鋳肌荒れ","explanation":"資料の記載：５．鋳肌荒れ，焼き付き\n\n補足：埋没材の加熱や金属融解を適切に行う。","source":"資料11 p8（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p8（赤字）","path":"assets/sourcepages/s11_p8.jpg"}]},{"id":"q262","number":262,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"鋳造体の表面が粗造になった状態として示される2つの鋳造欠陥は何か。","answer":"鋳肌荒れ・焼き付き","explanation":"資料の記載：5．鋳肌荒れ，焼き付き／鋳造体の表面が粗造になった状態\n\n補足：鋳肌荒れとともに表面の鋳造欠陥として示される。","source":"資料11 p8（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p8（赤字）","path":"assets/sourcepages/s11_p8.jpg"}]},{"id":"q263","number":263,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"鋳造後、合金の性質を調整するため必要に応じて行う処理は何か。","answer":"熱処理","explanation":"資料の記載：４．（必要に応じて）熱処理\n\n補足：機械的性質を調整する。","source":"資料11 p10（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p10（赤字）","path":"assets/sourcepages/s11_p10.jpg"}]},{"id":"q264","number":264,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"金合金などを700〜800℃で溶体化処理した後、水中で急冷する熱処理を何というか。","answer":"軟化熱処理","explanation":"資料の記載：軟化熱処理：溶体化処理（700～800℃）後，水中で急冷\n\n補足：金合金を軟らかくし、延性を高める。","source":"資料11 p10（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p10（赤字）","path":"assets/sourcepages/s11_p10.jpg"}]},{"id":"q265","number":265,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"金合金などを350〜400℃で10〜30分係留した後、徐冷する熱処理を何というか。","answer":"硬化熱処理","explanation":"資料の記載：硬化熱処理：350～400℃で10～30分係留後，徐冷\n\n補足：硬さと強さを高める。","source":"資料11 p10（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p10（赤字）","path":"assets/sourcepages/s11_p10.jpg"}]},{"id":"q266","number":266,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"クラウンの隣接面接触関係を確認する際、デンタルフロスや咬合紙とともに用いる器具は何か。","answer":"コンタクトゲージ","explanation":"資料の記載：コンタクトゲージ，デンタルフロス，咬合紙を用いて確認\n\n補足：デンタルフロス、咬合紙も用いる。","source":"資料11 p12（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p12（赤字）","path":"assets/sourcepages/s11_p12.jpg"}]},{"id":"q267","number":267,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"鋳造体の研磨法のうち、最も一般的な方法は何か。","answer":"機械的研磨法","explanation":"資料の記載：１．機械的研磨法：最も一般的\n\n補足：荒研磨、仕上げ研磨、艶出し研磨へ進む。","source":"資料11 p13（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料11 p13（赤字）","path":"assets/sourcepages/s11_p13.jpg"}]},{"id":"q268","number":268,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"クラウンを確認のため一時的に装着することを何というか。","answer":"仮着","explanation":"資料の記載：仮着：確認のための一時装着\n\n補足：問題がなければ仮着せずに合着する場合もある。","source":"資料12 p5（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p5（赤字）","path":"assets/sourcepages/s12_p5.jpg"}]},{"id":"q269","number":269,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"歯科用セメントを用いてクラウンやブリッジを口腔内へ恒久的に装着することを何というか。","answer":"合着","explanation":"資料の記載：「合着」：歯科用セメントをでクラウン、ブリッジなどを口腔内へ恒久的\n\n補足：広義には維持様式にかかわらず装着操作を合着という。","source":"資料12 p10（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p10（赤字）","path":"assets/sourcepages/s12_p10.jpg"}]},{"id":"q270","number":270,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"被着体表面の微細な凹凸への嵌合効力や分子間の結合によって、被着体同士を結び付けることを何というか。","answer":"接着","explanation":"資料の記載：「接着」：被着体表面の微細な凹凸に入り込んだ嵌合効力、\n\n補足：被着体表面の微細な凹凸への入り込みも利用する。","source":"資料12 p10（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p10（赤字）","path":"assets/sourcepages/s12_p10.jpg"}]},{"id":"q271","number":271,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"リン酸亜鉛セメントが歯冠補綴装置を維持する嵌合効力を何というか。","answer":"嵌合効力（アンカー効果）","explanation":"資料の記載：例）リン酸亜鉛セメントは嵌合効力（アンカー効果）のみで歯冠補綴装置を維持\n\n補足：合着の主な維持機構。","source":"資料12 p10（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p10（赤字）","path":"assets/sourcepages/s12_p10.jpg"}]},{"id":"q272","number":272,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"次亜塩素酸ナトリウムゲル法で露出コラーゲンを除去すると、何が露出するか。","answer":"ハイドロキシアパタイト","explanation":"資料の記載：露出コラーゲンを溶解除去し、ハイドロキシアパタイトを露出\n\n補足：残留NaOClはスルフィン酸塩で還元する。","source":"資料12 p20（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p20（赤字）","path":"assets/sourcepages/s12_p20.jpg"}]},{"id":"q273","number":273,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"患者や術者が仮着期間中に確認する内容として、資料ではどのような問いが示されているか。","answer":"本当に問題なく使えるか","explanation":"資料の記載：３）患者・術者が経過確認したい場合＝『本当に問題なく使えるか？』\n\n補足：咬合、適合状態、患者の使用感や長期予後を確認する。","source":"資料12 p7（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p7（赤字）","path":"assets/sourcepages/s12_p7.jpg"}]},{"id":"q274","number":274,"unit":"第7単元 赤字最重要チェック","importance":3,"type":"short","question":"仮着の目的で確認する項目は、どの2つの装着段階に分けて示されているか。","answer":"プロビジョナル装着時・調整済みクラウン／ブリッジ","explanation":"資料の記載：【プロビジョナル装着時】／【調整済みクラウン・ブリッジ】\n\n補足：それぞれ確認項目が異なる。","source":"資料12 p7（赤字）","image":null,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p7（赤字）","path":"assets/sourcepages/s12_p7.jpg"}]},{"id":"q275","number":275,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図中のAで示すフィニッシュラインは何か。","answer":"ナイフエッジ","explanation":"フィニッシュラインは材料厚、適合性、応力集中に応じて選択する。","source":"中間試験過去問・演習問題1-15","image":"assets/figures/p44_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"中間試験過去問 p2","path":"assets/sourcepages/past_p2.jpg"}]},{"id":"q276","number":276,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図中のBで示すフィニッシュラインは何か。","answer":"シャンファー","explanation":"フィニッシュラインは材料厚、適合性、応力集中に応じて選択する。","source":"中間試験過去問・演習問題1-15","image":"assets/figures/p44_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"中間試験過去問 p2","path":"assets/sourcepages/past_p2.jpg"}]},{"id":"q277","number":277,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図中のCで示すフィニッシュラインは何か。","answer":"ディープシャンファー","explanation":"フィニッシュラインは材料厚、適合性、応力集中に応じて選択する。","source":"中間試験過去問・演習問題1-15","image":"assets/figures/p44_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"中間試験過去問 p2","path":"assets/sourcepages/past_p2.jpg"}]},{"id":"q278","number":278,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図中のDで示すフィニッシュラインは何か。","answer":"ラウンデッドショルダー","explanation":"フィニッシュラインは材料厚、適合性、応力集中に応じて選択する。","source":"中間試験過去問・演習問題1-15","image":"assets/figures/p44_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"中間試験過去問 p2","path":"assets/sourcepages/past_p2.jpg"}]},{"id":"q279","number":279,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図中のEで示すフィニッシュラインは何か。","answer":"ショルダー","explanation":"フィニッシュラインは材料厚、適合性、応力集中に応じて選択する。","source":"中間試験過去問・演習問題1-15","image":"assets/figures/p44_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"中間試験過去問 p2","path":"assets/sourcepages/past_p2.jpg"}]},{"id":"q280","number":280,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図中のFで示すフィニッシュラインは何か。","answer":"ベベルドショルダー","explanation":"フィニッシュラインは材料厚、適合性、応力集中に応じて選択する。","source":"中間試験過去問・演習問題1-15","image":"assets/figures/p44_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"中間試験過去問 p2","path":"assets/sourcepages/past_p2.jpg"}]},{"id":"q281","number":281,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図の咬合様式を何というか。","answer":"cuspid protected occlusion","explanation":"作業側犬歯のみが接触し、臼歯部を離開させる。","source":"演習問題1-01","image":"assets/figures/occlusion_clean.jpg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-01（元ページ）","path":"assets/sourcepages/exercise_p2.jpg"}]},{"id":"q282","number":282,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"写真の器具を用いる検査は何か。","answer":"歯間離開度検査","explanation":"コンタクトゲージで隣接面接触の強さを確認する。","source":"演習問題1-03","image":"assets/figures/p45_2.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-03（元ページ）","path":"assets/sourcepages/exercise_p4.jpg"}]},{"id":"q283","number":283,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"写真の切削機器を何というか。","answer":"エアタービン","explanation":"高速回転切削器具で、注水下で使用する。","source":"演習問題1-04","image":"assets/figures/p46_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-04（元ページ）","path":"assets/sourcepages/exercise_p5.jpg"}]},{"id":"q284","number":284,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"写真の操作を何というか。","answer":"歯肉圧排","explanation":"印象採得前に歯肉溝を開きフィニッシュラインを明示する。","source":"演習問題1-06","image":"assets/figures/p46_2.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-06（元ページ）","path":"assets/sourcepages/exercise_p7.jpg"}]},{"id":"q285","number":285,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"写真のトレーを何というか。","answer":"個歯トレー","explanation":"支台歯周囲の印象材厚を均一に保つ。","source":"演習問題1-07","image":"assets/figures/p47_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-07（元ページ）","path":"assets/sourcepages/exercise_p8.jpg"}]},{"id":"q286","number":286,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"写真の印象法を何というか。","answer":"咬合印象法","explanation":"上下顎と咬合関係を同時に記録する。","source":"演習問題1-08","image":"assets/figures/p47_2.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-08（元ページ）","path":"assets/sourcepages/exercise_p9.jpg"}]},{"id":"q287","number":287,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"写真の作業用模型を何というか。","answer":"可撤歯型式模型","explanation":"歯型を取り外して隣接面や辺縁を操作できる。","source":"演習問題1-10","image":"assets/figures/p48_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-10（元ページ）","path":"assets/sourcepages/exercise_p11.jpg"}]},{"id":"q288","number":288,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"写真の歯肉付き模型を何というか。","answer":"歯肉付き模型","explanation":"エマージェンスプロファイル設定の参考となる。","source":"演習問題1-11","image":"assets/figures/p48_2.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-11（元ページ）","path":"assets/sourcepages/exercise_p12.jpg"}]},{"id":"q289","number":289,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"写真の操作を何というか。","answer":"フェイスボウトランスファー","explanation":"上顎歯列の頭蓋・顎関節に対する位置を記録する。","source":"演習問題1-13","image":"assets/figures/p49_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-13（元ページ）","path":"assets/sourcepages/exercise_p14.jpg"}]},{"id":"q290","number":290,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"写真の青い通路を何というか。","answer":"エアベント","explanation":"鋳型内の空気を逃がして背圧多孔を防止する。","source":"演習問題1-14","image":"assets/figures/p49_2.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-14（元ページ）","path":"assets/sourcepages/exercise_p15.jpg"}]},{"id":"q291","number":291,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"写真の金属面に次に行う処理は何か。","answer":"アルミナサンドブラスト処理","explanation":"前装用レジンの接着前に表面を粗造化する。","source":"演習問題1-16","image":"assets/figures/p50_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-16（元ページ）","path":"assets/sourcepages/exercise_p17.jpg"}]},{"id":"q292","number":292,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"陶材築盛後に行う操作は何か。","answer":"コンデンス","explanation":"余剰水分と気泡を除き陶材粒子を緊密化する。","source":"演習問題1-17","image":"assets/figures/p50_2.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-17（元ページ）","path":"assets/sourcepages/exercise_p18.jpg"}]},{"id":"q293","number":293,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"写真の修復物を何というか。","answer":"ラミネートベニア","explanation":"薄い陶材シェルを唇面へ接着する。","source":"演習問題1-18","image":"assets/figures/p51_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-18（元ページ）","path":"assets/sourcepages/exercise_p19.jpg"}]},{"id":"q294","number":294,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"矢印部の鋳造欠陥は何か。","answer":"突起","explanation":"埋没材中の気泡が原因で生じる。","source":"演習問題1-19","image":"assets/figures/p51_2.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-19（元ページ）","path":"assets/sourcepages/exercise_p20.jpg"}]},{"id":"q295","number":295,"unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"写真の材料から作る冠を何というか。","answer":"CAD/CAM冠","explanation":"高度重合済みレジンブロックを切削して製作する。","source":"演習問題1-20","image":"assets/figures/p52_1.jpeg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"演習問題1-20（元ページ）","path":"assets/sourcepages/exercise_p21.jpg"}]},{"id":"sourcefig_contour","unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図のA、B、Cはそれぞれ何カントゥアか。","answer":"A：ノーマルカントゥア、B：オーバーカントゥア、C：アンダーカントゥア","explanation":"資料の図では、Aは自浄性とマッサージ効果が両立する。Bは自浄性が悪く、汚れがたまりやすい。Cは辺縁歯肉への刺激が大きい。","source":"資料7 p6","image":"assets/figures/source_s7_contour_ABC.jpg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p6","path":"assets/sourcepages/s7_p6.jpg"}],"number":296,"imageAuto":true},{"id":"sourcefig_contactheight","unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図A〜Dの接触状態をそれぞれ答えよ。","answer":"A：適正な接触状態、B：接触点が低すぎる接触状態、C：接触点が高すぎる接触状態、D：辺縁隆線の高さの不一致","explanation":"接触点を正しく回復し、適切な鼓形空隙を確保する。","source":"資料7 p7","image":"assets/figures/source_s7_contact_ABCD.jpg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p7","path":"assets/sourcepages/s7_p7.jpg"}],"number":297,"imageAuto":true},{"id":"sourcefig_buccolingual","unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図A〜Cの頰舌的な接触状態をそれぞれ答えよ。","answer":"A：適正な頰舌的接触状態、B：極端な点状接触、C：頰舌的に広すぎる接触状態","explanation":"頰舌方向でも、接触点の位置と広がりを適切に回復する。","source":"資料7 p7","image":"assets/figures/source_s7_buccolingual_ABC.jpg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p7","path":"assets/sourcepages/s7_p7.jpg"}],"number":298,"imageAuto":true},{"id":"sourcefig_contactshape","unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図A、Bの接触点の形態をそれぞれ答えよ。","answer":"A：上下的な楕円形、B：頰舌的な楕円形","explanation":"Aは前歯、Bは臼歯の接触点を示す。","source":"資料7 p8","image":"assets/figures/source_s7_contactshape_AB.jpg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料7 p8","path":"assets/sourcepages/s7_p8.jpg"}],"number":299,"imageAuto":true},{"id":"sourcefig_occlusalborder","unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図A〜Cで、対合歯と接触する部位をそれぞれ答えよ。","answer":"A：金属、B：陶材、C：陶材と金属の境界部","explanation":"Cのように陶材と金属の境界部で接触させるのは好ましくない。","source":"資料9 p16","image":"assets/figures/source_s9_occlusalborder_ABC.jpg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p16","path":"assets/sourcepages/s9_p16.jpg"}],"number":300,"imageAuto":true},{"id":"sourcefig_copingdesign","unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図A〜Cに示すメタルコーピングの具備条件をそれぞれ答えよ。","answer":"A：築盛陶材の厚みを均一にする、B：メタルコーピングを包みこむようにして亀裂・破折を防止する、C：曲面形態に仕上げる","explanation":"陶材の支持と破折防止のために、メタルコーピングの形態を整える。","source":"資料9 p17","image":"assets/figures/source_s9_copingdesign_ABC.jpg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p17","path":"assets/sourcepages/s9_p17.jpg"}],"number":301,"imageAuto":true},{"id":"sourcefig_margin","unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図A〜Dのマージンデザインをそれぞれ答えよ。","answer":"A：ロングデザイン、B：ショートデザイン、C：ミディアムデザイン、D：インビジブルメタルマージン","explanation":"資料9のメタルコーピングの設計で示されているマージンデザイン。","source":"資料9 p18","image":"assets/figures/source_s9_margin_ABCD.jpg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p18","path":"assets/sourcepages/s9_p18.jpg"}],"number":302,"imageAuto":true},{"id":"sourcefig_veneerrange","unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図A〜Dの前装範囲をそれぞれ答えよ。","answer":"A：前歯部パーシャルベーク型、B：前歯部フルベーク型、C：臼歯部パーシャルベーク型、D：臼歯部フルベーク型","explanation":"前歯部・臼歯部それぞれに、パーシャルベーク型とフルベーク型がある。","source":"資料9 p16","image":"assets/figures/source_s9_veneerrange_ABCD.jpg","options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料9 p16","path":"assets/sourcepages/s9_p16.jpg"}],"number":303,"imageAuto":true},{"id":"sourcefig_bonding","unit":"第8単元 図表・写真で答える用語問題","importance":3,"type":"short","question":"図A〜Dの象牙質接着システムをそれぞれ答えよ。","answer":"A：3ステップ接着システム（エッチ＆リンスシステム）、B：2ステップセルフエッチングシステム、C：1ステップセルフエッチングシステム、D：セルフアドヒーシブ型レジンセメント","explanation":"資料では、3step→2step→1step→Self-adhesiveの順に簡便化し、チェアタイムが短縮すると示されている。","source":"資料12 p19","image":"assets/figures/source_s12_bonding_ABCD.jpg","imageAuto":true,"options":[],"correct":[],"custom":false,"sourcePages":[{"label":"資料12 p19","path":"assets/sourcepages/s12_p19.jpg"}],"number":304},{"id":"q296","number":305,"label":"1-01","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"図の咬合様式はどれか。1つ選べ。","answer":"d","explanation":"作業側犬歯のみが接触して臼歯部を離開させるため。","source":"演習問題1","image":"assets/figures/occlusion_clean.jpg","options":[{"key":"a","text":"group function"},{"key":"b","text":"lingualized occlusion"},{"key":"c","text":"monoplane occlusion"},{"key":"d","text":"cuspid protected occlusion"},{"key":"e","text":"fully bilateral balanced occlusion"}],"correct":["d"],"custom":false,"sourcePages":[{"label":"演習問題1-01（元ページ）","path":"assets/sourcepages/exercise_p2.jpg"}]},{"id":"q297","number":306,"label":"1-02","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真の状態を放置すると生じる二次性障害はどれか。1つ選べ。","answer":"c","explanation":"歯列欠損により隣在歯・対合歯が移動し、早期接触を生じる。","source":"演習問題1","image":"assets/figures/p53_1.jpeg","options":[{"key":"a","text":"開口困難"},{"key":"b","text":"審美不良"},{"key":"c","text":"早期接触"},{"key":"d","text":"咀嚼筋痛"},{"key":"e","text":"咀嚼困難"}],"correct":["c"],"custom":false,"sourcePages":[{"label":"演習問題1-02（元ページ）","path":"assets/sourcepages/exercise_p3.jpg"}]},{"id":"q298","number":307,"label":"1-03","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真の材料の使用目的はどれか。1つ選べ。","answer":"e","explanation":"コンタクトゲージは歯間離開度を評価する。","source":"演習問題1","image":"assets/figures/p45_2.jpeg","options":[{"key":"a","text":"嚥下機能検査"},{"key":"b","text":"構音機能検査"},{"key":"c","text":"適合試験検査"},{"key":"d","text":"引き抜き試験"},{"key":"e","text":"歯間離開度検査"}],"correct":["e"],"custom":false,"sourcePages":[{"label":"演習問題1-03（元ページ）","path":"assets/sourcepages/exercise_p4.jpg"}]},{"id":"q299","number":308,"label":"1-04","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真の機器の特徴はどれか。1つ選べ。","answer":"b","explanation":"高速回転による発熱を防ぐため注水下で用いる。","source":"演習問題1","image":"assets/figures/p46_1.jpeg","options":[{"key":"a","text":"逆回転で切削できる"},{"key":"b","text":"必ず注水下で使用する"},{"key":"c","text":"フィンガーレストは必要ない"},{"key":"d","text":"回転数は数百〜数千回転/分"},{"key":"e","text":"適切な切削圧は500〜600gf"}],"correct":["b"],"custom":false,"sourcePages":[{"label":"演習問題1-04（元ページ）","path":"assets/sourcepages/exercise_p5.jpg"}]},{"id":"q300","number":309,"label":"1-05","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"ジャケットクラウンのフィニッシュライン形成に用いる器具はどれか。1つ選べ。","answer":"a","explanation":"アは先端が丸いテーパー型でディープシャンファー形成に適する。","source":"演習問題1","image":"assets/figures/p55_2.jpeg","options":[{"key":"a","text":"ア"},{"key":"b","text":"イ"},{"key":"c","text":"ウ"},{"key":"d","text":"エ"},{"key":"e","text":"オ"}],"correct":["a"],"custom":false,"sourcePages":[{"label":"演習問題1-05（元ページ）","path":"assets/sourcepages/exercise_p6.jpg"}]},{"id":"q301","number":310,"label":"1-06","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真の歯肉圧排で正しいのはどれか。1つ選べ。","answer":"e","explanation":"圧排糸は印象直前に除去し、開いた歯肉溝へ印象材を流す。","source":"演習問題1","image":"assets/figures/p46_2.jpeg","options":[{"key":"a","text":"歯周組織を保護する"},{"key":"b","text":"隣在歯にも挿入する"},{"key":"c","text":"上皮性付着を剥離する"},{"key":"d","text":"水で湿らせて挿入する"},{"key":"e","text":"印象採得の直前に除去する"}],"correct":["e"],"custom":false,"sourcePages":[{"label":"演習問題1-06（元ページ）","path":"assets/sourcepages/exercise_p7.jpg"}]},{"id":"q302","number":311,"label":"1-07","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真のトレーを用いる目的はどれか。1つ選べ。","answer":"e","explanation":"個歯トレーで支台歯周囲の印象材厚を均一にし、辺縁を明瞭に記録する。","source":"演習問題1","image":"assets/figures/p47_1.jpeg","options":[{"key":"a","text":"形成量の確認"},{"key":"b","text":"咬合採得の省略"},{"key":"c","text":"カントゥアの確認"},{"key":"d","text":"歯肉溝滲出液の抑制"},{"key":"e","text":"フィニッシュラインの明示"}],"correct":["e"],"custom":false,"sourcePages":[{"label":"演習問題1-07（元ページ）","path":"assets/sourcepages/exercise_p8.jpg"}]},{"id":"q303","number":312,"label":"1-08","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真の印象法の特徴はどれか。1つ選べ。","answer":"d","explanation":"閉口状態で上下顎と咬合関係を同時記録するため。","source":"演習問題1","image":"assets/figures/p47_2.jpeg","options":[{"key":"a","text":"開口印象である"},{"key":"b","text":"歯型の寸法精度が高い"},{"key":"c","text":"印象後に咬合採得を行う"},{"key":"d","text":"咬合関係の再現精度が高い"},{"key":"e","text":"上下顎同時に石膏を注入できる"}],"correct":["d"],"custom":false,"sourcePages":[{"label":"演習問題1-08（元ページ）","path":"assets/sourcepages/exercise_p9.jpg"}]},{"id":"q304","number":313,"label":"1-09","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真の操作の次に行うのはどれか。1つ選べ。","answer":"d","explanation":"印象内へレジンを填入した後、支台歯へ圧接してプロビジョナルを形成する。","source":"演習問題1","image":"assets/figures/p58_1.jpeg","options":[{"key":"a","text":"水洗"},{"key":"b","text":"水中浸漬"},{"key":"c","text":"トリミング"},{"key":"d","text":"支台歯への圧接"},{"key":"e","text":"支台歯への分離材塗布"}],"correct":["d"],"custom":false,"sourcePages":[{"label":"演習問題1-09（元ページ）","path":"assets/sourcepages/exercise_p10.jpg"}]},{"id":"q305","number":314,"label":"1-10","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真の模型の特徴で正しいのはどれか。1つ選べ。","answer":"e","explanation":"可撤歯型を外せるため隣接面やマージンの操作が容易。","source":"演習問題1","image":"assets/figures/p48_1.jpeg","options":[{"key":"a","text":"副歯型を併用する"},{"key":"b","text":"歯型の浮き上がりを抑制する"},{"key":"c","text":"ダイロックトレーを使用する"},{"key":"d","text":"歯型分割後に二次石膏を注入する"},{"key":"e","text":"隣接面のワックスアップが容易である"}],"correct":["e"],"custom":false,"sourcePages":[{"label":"演習問題1-10（元ページ）","path":"assets/sourcepages/exercise_p11.jpg"}]},{"id":"q306","number":315,"label":"1-11","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真の模型の特徴で正しいのはどれか。1つ選べ。","answer":"e","explanation":"人工歯肉により歯頸部の立ち上がりを確認できる。","source":"演習問題1","image":"assets/figures/p48_2.jpeg","options":[{"key":"a","text":"光学印象の精度が向上する"},{"key":"b","text":"シェード選択の参考になる"},{"key":"c","text":"個歯トレー印象法で製作される"},{"key":"d","text":"歯列内の支台歯位置の再現精度に優れる"},{"key":"e","text":"エマージェンスプロファイル設定の参考となる"}],"correct":["e"],"custom":false,"sourcePages":[{"label":"演習問題1-11（元ページ）","path":"assets/sourcepages/exercise_p12.jpg"}]},{"id":"q307","number":316,"label":"1-12","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真の作業の目的はどれか。1つ選べ。","answer":"d","explanation":"咬合器装着前の咬合記録の余剰を削り、過高を防ぐ。","source":"演習問題1","image":"assets/figures/p60_1.jpeg","options":[{"key":"a","text":"形成量の確認"},{"key":"b","text":"食片圧入の防止"},{"key":"c","text":"アンダーカットの除去"},{"key":"d","text":"補綴装置の過高の防止"},{"key":"e","text":"補綴装置の適合性の向上"}],"correct":["d"],"custom":false,"sourcePages":[{"label":"演習問題1-12（元ページ）","path":"assets/sourcepages/exercise_p13.jpg"}]},{"id":"q308","number":317,"label":"1-13","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真の操作で記録するのはどれか。1つ選べ。","answer":"d","explanation":"フェイスボウは上顎歯列と顎関節・頭蓋の位置関係を記録する。","source":"演習問題1","image":"assets/figures/p49_1.jpeg","options":[{"key":"a","text":"開口量"},{"key":"b","text":"蝶番軸"},{"key":"c","text":"ベネット運動"},{"key":"d","text":"上顎歯列の位置"},{"key":"e","text":"下顎歯列の位置"}],"correct":["d"],"custom":false,"sourcePages":[{"label":"演習問題1-13（元ページ）","path":"assets/sourcepages/exercise_p14.jpg"}]},{"id":"q309","number":318,"label":"1-14","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"矢印の構造が防止するのはどれか。1つ選べ。","answer":"d","explanation":"エアベントが鋳型内の空気を逃がす。","source":"演習問題1","image":"assets/figures/p49_2.jpeg","options":[{"key":"a","text":"鋳巣"},{"key":"b","text":"鋳バリ"},{"key":"c","text":"鋳肌荒れ"},{"key":"d","text":"背圧多孔"},{"key":"e","text":"湯ざかい"}],"correct":["d"],"custom":false,"sourcePages":[{"label":"演習問題1-14（元ページ）","path":"assets/sourcepages/exercise_p15.jpg"}]},{"id":"q310","number":319,"label":"1-15","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真のクラウンに適切な辺縁形態はどれか。2つ選べ。","answer":"d・e","explanation":"CAD/CAM冠では材料厚を確保し、鋭角を避ける。","source":"演習問題1","image":"assets/figures/p62_1.jpeg","options":[{"key":"a","text":"ショルダー"},{"key":"b","text":"シャンファー"},{"key":"c","text":"ナイフエッジ"},{"key":"d","text":"ディープシャンファー"},{"key":"e","text":"ラウンデッドショルダー"}],"correct":["d","e"],"custom":false,"sourcePages":[{"label":"演習問題1-15（元ページ）","path":"assets/sourcepages/exercise_p16.jpg"}]},{"id":"q311","number":320,"label":"1-16","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真のメタルフレームに次に行うのはどれか。1つ選べ。","answer":"e","explanation":"まずアルミナで表面を粗造化し、その後プライマーを塗布する。","source":"演習問題1","image":"assets/figures/p50_1.jpeg","options":[{"key":"a","text":"ディギャッシング"},{"key":"b","text":"フッ化水素酸処理"},{"key":"c","text":"オペークレジン塗布"},{"key":"d","text":"金属接着性プライマー塗布"},{"key":"e","text":"アルミナサンドブラスト処理"}],"correct":["e"],"custom":false,"sourcePages":[{"label":"演習問題1-16（元ページ）","path":"assets/sourcepages/exercise_p17.jpg"}]},{"id":"q312","number":321,"label":"1-17","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"陶材築盛後に次に行うのはどれか。1つ選べ。","answer":"c","explanation":"築盛陶材の水分・気泡を除いて粒子を緊密化する。","source":"演習問題1","image":"assets/figures/p50_2.jpeg","options":[{"key":"a","text":"真空焼成"},{"key":"b","text":"大気焼成"},{"key":"c","text":"コンデンス"},{"key":"d","text":"グレージング"},{"key":"e","text":"ディギャッシング"}],"correct":["c"],"custom":false,"sourcePages":[{"label":"演習問題1-17（元ページ）","path":"assets/sourcepages/exercise_p18.jpg"}]},{"id":"q313","number":322,"label":"1-18","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真の修復物の特徴で正しいのはどれか。1つ選べ。","answer":"c","explanation":"ポーセレンラミネートベニアは主に耐火模型法で製作する。","source":"演習問題1","image":"assets/figures/p51_1.jpeg","options":[{"key":"a","text":"仮着して色調を確認する"},{"key":"b","text":"歯質削除は象牙質まで行う"},{"key":"c","text":"陶材焼成は耐火模型上で行う"},{"key":"d","text":"辺縁形態はショルダーとする"},{"key":"e","text":"グラスアイオノマーセメントで装着する"}],"correct":["c"],"custom":false,"sourcePages":[{"label":"演習問題1-18（元ページ）","path":"assets/sourcepages/exercise_p19.jpg"}]},{"id":"q314","number":323,"label":"1-19","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真の鋳造欠陥の原因はどれか。1つ選べ。","answer":"e","explanation":"埋没材中の気泡が鋳型のくぼみとなり、鋳造体では突起となる。","source":"演習問題1","image":"assets/figures/p51_2.jpeg","options":[{"key":"a","text":"金属の過熱"},{"key":"b","text":"金属量の不足"},{"key":"c","text":"鋳造圧の不足"},{"key":"d","text":"埋没材の亀裂"},{"key":"e","text":"埋没材中の気泡"}],"correct":["e"],"custom":false,"sourcePages":[{"label":"演習問題1-19（元ページ）","path":"assets/sourcepages/exercise_p20.jpg"}]},{"id":"q315","number":324,"label":"1-20","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真のクラウン装着時に必要な内面処理はどれか。1つ選べ。","answer":"d","explanation":"CAD/CAM用コンポジットレジン冠はアルミナサンドブラスト後にシラン処理する。","source":"演習問題1","image":"assets/figures/p52_1.jpeg","options":[{"key":"a","text":"希硫酸処理"},{"key":"b","text":"次亜塩素酸処理"},{"key":"c","text":"フッ化水素酸処理"},{"key":"d","text":"アルミナサンドブラスト処理"},{"key":"e","text":"ガラスビーズサンドブラスト処理"}],"correct":["d"],"custom":false,"sourcePages":[{"label":"演習問題1-20（元ページ）","path":"assets/sourcepages/exercise_p21.jpg"}]},{"id":"q316","number":325,"label":"118B-40","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"CAD/CAM用コンポジットレジンでエナメル質より小さいのはどれか。1つ選べ。","answer":"a","explanation":"CAD/CAM用コンポジットレジンの弾性係数はエナメル質より小さい。","source":"資料8末尾","image":null,"options":[{"key":"a","text":"弾性係数"},{"key":"b","text":"引張強さ"},{"key":"c","text":"曲げ強さ"},{"key":"d","text":"熱膨張係数"},{"key":"e","text":"破壊靱性値"}],"correct":["a"],"custom":false,"sourcePages":[{"label":"資料8末尾","path":"assets/sourcepages/s8_plast.jpg"}]},{"id":"q317","number":326,"label":"119A-15","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"CAD/CAMのCADはComputer Aided（ ）を意味する。（ ）に入るのはどれか。1つ選べ。","answer":"b","explanation":"CADはComputer Aided Designの略。","source":"資料8末尾","image":null,"options":[{"key":"a","text":"Data"},{"key":"b","text":"Design"},{"key":"c","text":"Device"},{"key":"d","text":"Direction"},{"key":"e","text":"Digitizing"}],"correct":["b"],"custom":false,"sourcePages":[{"label":"資料8末尾","path":"assets/sourcepages/s8_plast.jpg"}]},{"id":"q318","number":327,"label":"118C-61","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"写真Aのメタルフレーム試適から写真Bの完成レジン前装冠までに行うのはどれか。2つ選べ。","answer":"d・e","explanation":"レジン前装では金属表面をサンドブラストし、金属接着性プライマーを用いる。","source":"資料9末尾","image":"assets/figures/p66_1.jpeg","options":[{"key":"a","text":"グレージング"},{"key":"b","text":"フッ化水素酸処理"},{"key":"c","text":"オペーク陶材の築盛"},{"key":"d","text":"サンドブラスト処理"},{"key":"e","text":"メタルプライマーの塗布"}],"correct":["d","e"],"custom":false,"sourcePages":[{"label":"資料9末尾","path":"assets/sourcepages/s9_plast.jpg"}]},{"id":"q319","number":328,"label":"119C-79改変","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"レジン前装ブリッジのフレームワーク完成後に行う操作のうち、3番目はどれか。1つ選べ。","answer":"c","explanation":"順序はサンドブラスト→金属プライマー→オペークレジン→デンティン色レジン→形態修正。","source":"資料9末尾","image":"assets/figures/p67_1.jpeg","options":[{"key":"a","text":"歯冠形態の修正"},{"key":"b","text":"アルミナサンドブラスト処理"},{"key":"c","text":"オペークレジンの塗布と重合"},{"key":"d","text":"金属接着性プライマーの塗布"},{"key":"e","text":"デンティン色レジンの築盛と重合"}],"correct":["c"],"custom":false,"sourcePages":[{"label":"資料9末尾","path":"assets/sourcepages/s9_plast.jpg"}]},{"id":"q320","number":329,"label":"119C-78","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"陶材焼付用金合金と金属焼付用陶材の比較で、陶材が大きい値はどれか。2つ選べ。","answer":"a・c","explanation":"陶材は硬く弾性係数が大きいが、密度・引張強さ・熱膨張係数は金合金より小さい。","source":"資料9末尾","image":null,"options":[{"key":"a","text":"硬さ"},{"key":"b","text":"密度"},{"key":"c","text":"弾性係数"},{"key":"d","text":"引張強さ"},{"key":"e","text":"熱膨張係数"}],"correct":["a","c"],"custom":false,"sourcePages":[{"label":"資料9末尾","path":"assets/sourcepages/s9_plast.jpg"}]},{"id":"q321","number":330,"label":"118B-61","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"金属焼付用陶材の焼成温度で適切なのはどれか。1つ選べ。","answer":"b","explanation":"金属焼付用陶材の焼成温度は約950℃。","source":"資料9末尾","image":null,"options":[{"key":"a","text":"700℃"},{"key":"b","text":"950℃"},{"key":"c","text":"1,200℃"},{"key":"d","text":"1,350℃"},{"key":"e","text":"1,500℃"}],"correct":["b"],"custom":false,"sourcePages":[{"label":"資料9末尾","path":"assets/sourcepages/s9_plast.jpg"}]},{"id":"q322","number":331,"label":"119B-69","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"レジン前装冠と比較したオールセラミッククラウンの特徴で正しいのはどれか。3つ選べ。","answer":"b・c・e","explanation":"セラミックは耐摩耗性・色調再現性に優れ、金属を使用しない。","source":"資料10末尾","image":"assets/figures/p68_1.jpeg","options":[{"key":"a","text":"着色しやすい"},{"key":"b","text":"耐摩耗性が高い"},{"key":"c","text":"色調再現性が高い"},{"key":"d","text":"プラークが付着しやすい"},{"key":"e","text":"金属アレルギー患者に適用できる"}],"correct":["b","c","e"],"custom":false,"sourcePages":[{"label":"資料10末尾","path":"assets/sourcepages/s10_plast.jpg"}]},{"id":"q323","number":332,"label":"119C-59","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"オールセラミッククラウンのコーピング試適後に行うのはどれか。2つ選べ。","answer":"a・d","explanation":"コーピング完成後は歯冠色陶材を築盛し、最終的にグレージングする。","source":"資料10末尾","image":"assets/figures/p69_1.jpeg","options":[{"key":"a","text":"グレージング"},{"key":"b","text":"CAMによる加工"},{"key":"c","text":"コーピングの焼成"},{"key":"d","text":"歯冠色陶材の築盛"},{"key":"e","text":"ディギャッシング"}],"correct":["a","d"],"custom":false,"sourcePages":[{"label":"資料10末尾","path":"assets/sourcepages/s10_plast.jpg"}]},{"id":"q324","number":333,"label":"102A-54","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"酸性基としてCOOHが関与するのはどれか。2つ選べ。","answer":"c・d","explanation":"ポリカルボン酸のカルボキシ基（COOH）が関与する。","source":"資料12末尾","image":null,"options":[{"key":"a","text":"シリケートセメント"},{"key":"b","text":"リン酸亜鉛セメント"},{"key":"c","text":"ポリカルボキシレートセメント"},{"key":"d","text":"グラスアイオノマーセメント"},{"key":"e","text":"酸化亜鉛ユージノールセメント"}],"correct":["c","d"],"custom":false,"sourcePages":[{"label":"資料12末尾","path":"assets/sourcepages/s12_plast.jpg"}]},{"id":"q325","number":334,"label":"101B-47","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"矯正用ブラケットの接着に用いるのはどれか。1つ選べ。","answer":"d","explanation":"ブラケット接着には高い接着力をもつ4-META系レジンセメントを用いる。","source":"資料12末尾","image":null,"options":[{"key":"a","text":"EBAセメント"},{"key":"b","text":"リン酸亜鉛セメント"},{"key":"c","text":"ポリカルボキシレートセメント"},{"key":"d","text":"4-META系レジンセメント"},{"key":"e","text":"酸化亜鉛ユージノールセメント"}],"correct":["d"],"custom":false,"sourcePages":[{"label":"資料12末尾","path":"assets/sourcepages/s12_plast.jpg"}]},{"id":"q326","number":335,"label":"113D-6","unit":"第9単元 指定選択問題","importance":3,"type":"mcq","question":"材料表面の水の接触角で評価するのはどれか。1つ選べ。","answer":"b","explanation":"接触角が小さいほどぬれ性が高い。","source":"資料12末尾","image":null,"options":[{"key":"a","text":"耐食性"},{"key":"b","text":"ぬれ性"},{"key":"c","text":"フロー"},{"key":"d","text":"溶解性"},{"key":"e","text":"表面粗さ"}],"correct":["b"],"custom":false,"sourcePages":[{"label":"資料12末尾","path":"assets/sourcepages/s12_plast.jpg"}]}],"units":[{"id":"u1","name":"第1単元 ワックスアップ・埋没","summary":["形態を作る操作がワックスアップ、ワックスパターンを埋没材で包み鋳型を作る操作が埋没。","接触点、鼓形空隙、エマージェンスプロファイル、ワックスアップ法、スプルーとエアベントを区別する。","0.05〜0.1mm、約1,000℃、約700℃などの数値を用語とセットで覚える。"],"range":[1,42]},{"id":"u2","name":"第2単元 ジャケットクラウン・CAD/CAM冠","summary":["ジャケットクラウンは歯冠色材料のみで製作する全部被覆冠。","支台歯形成では材料厚の確保と鋭角の回避が重要。","築盛法と機械加工法、CADとCAM、支台歯形成と内面処理を整理する。"],"range":[43,73]},{"id":"u3","name":"第3単元 レジン前装冠・陶材焼付冠","summary":["前装冠は金属冠の外観に触れる部分を歯冠色材料に置き換えたもの。","レジン前装冠はリテンションビーズ・アルミナサンドブラスト・金属接着性プライマーが中心。","陶材焼付冠は酸化膜、熱膨張係数、ディギャッシング、オペーク陶材、コンデンスが中心。"],"range":[74,111]},{"id":"u4","name":"第4単元 ラミネートベニア・オールセラミック","summary":["ラミネートベニアは薄い歯冠色シェルを主にエナメル質へ接着する。","耐火模型法、ロストワックス法、CAD/CAM法を区別する。","ジルコニアは半焼結体を加工し、完全焼結時の収縮をCADで補正する。"],"range":[112,137]},{"id":"u5","name":"第5単元 鋳造・鋳造欠陥・試適・研磨","summary":["鋳造欠陥は名称・形・原因・予防法をセットで覚える。","背圧多孔＝空気残留、突起＝埋没材中の気泡、鋳バリ＝埋没材の亀裂、湯ざかい＝金属流の癒合不良。","試適は隣接面・辺縁・咬合を確認し、研磨は荒研磨・仕上げ・艶出しへ進む。"],"range":[138,172]},{"id":"u6","name":"第6単元 仮着・合着・接着","summary":["仮着は確認のための一時装着、合着・接着は最終装着。","合着は主に嵌合効力、接着は機械的・物理的・化学的結合を利用する。","エナメル質、象牙質、金属、陶材、ジルコニア、CAD/CAMレジン冠で表面処理を区別する。"],"range":[173,210]},{"id":"u7","name":"第7単元 赤字最重要チェック","summary":["資料7〜12の赤文字を再確認する最重要単元。","既出内容でも赤字であれば重ねて出題している。","試験直前はこの単元を優先し、答えを一語または短い用語で即答する。"],"range":[211,274]},{"id":"u8","name":"第8単元 図表・写真で答える用語問題","summary":["図や写真を見て、選択肢なしで名称を答える。","フィニッシュライン6種は同じ図から繰り返し識別する。","図表は最初は非表示。必要なときだけ表示して考える。","資料中のA・B・Cなどの図を、そのまま名称対応問題にしている。"],"range":[275,304]},{"id":"u9","name":"第9単元 指定選択問題","summary":["演習問題1と資料末尾の指定国試問題を収録。","正解だけでなく、解説で選択理由を確認する。","写真問題では図を表示してから選択肢を検討する。"],"range":[305,335]}],"importanceLabels":{"1":"補足","2":"重要","3":"最重要"}};